-- Schema for Domain: land | Business: Agriculture | Version: v1_ecm
-- Generated on: 2026-05-01 16:23:38

-- ========= DATABASE =========
CREATE DATABASE IF NOT EXISTS `agriculture_ecm`.`land` COMMENT 'Authoritative domain for all land and soil asset data including field boundaries (GIS/ArcGIS-mapped), parcel ownership and lease records, soil health profiles (pH, EC, OM, CEC, NPK), soil sampling history, conservation practices, land use planning, and environmental monitoring. Integrates with Esri ArcGIS and John Deere Operations Center for RTK-accurate field mapping and GPS positioning. Supports BMP and ISO 14001 environmental compliance for sustainable land management.';

-- ========= TABLES =========
CREATE OR REPLACE TABLE `agriculture_ecm`.`land`.`field` (
    `field_id` BIGINT COMMENT 'Unique surrogate identifier for each agricultural field or paddock record in the land domain. Primary key for all field-level spatial identity, boundary history, and precision management zone definitions.',
    `farm_unit_id` BIGINT COMMENT 'Reference to the parent farm or agricultural operation to which this field belongs. Supports farm-level aggregation of field data for reporting and compliance.',
    `zone_id` BIGINT COMMENT 'Foreign key linking to weather.weather_zone. Business justification: Crop insurance underwriting (RMA), FSA program eligibility, and climate-based crop planning all require knowing which weather zone a field belongs to. Ag domain experts universally expect fields to ca',
    `arcgis_feature_code` STRING COMMENT 'Integration key referencing the corresponding feature object ID in the Esri ArcGIS geodatabase. Enables bidirectional synchronization between the lakehouse silver layer and the authoritative GIS system of record.',
    `aspect_direction` STRING COMMENT 'Predominant compass direction that the field slope faces, derived from DEM analysis in Esri ArcGIS. Influences solar radiation exposure, frost pocket risk, and crop variety selection. [ENUM-REF-CANDIDATE: N|NE|E|SE|S|SW|W|NW|flat — 9 candidates stripped; promote to reference product]',
    `boundary_effective_date` DATE COMMENT 'Date from which the current boundary version is considered authoritative and operationally active. Used for temporal field geometry queries and FSA acreage compliance reporting.',
    `boundary_geojson` STRING COMMENT 'GeoJSON-encoded polygon or multipolygon representing the RTK-accurate field boundary geometry sourced from Esri ArcGIS. Stores the current active boundary version. Supports FSA compliance boundary reporting and precision VRA zone delineation.',
    `boundary_version` STRING COMMENT 'Monotonically incrementing version number of the field boundary geometry, supporting temporal boundary change tracking for FSA compliance and historical spatial analysis. Incremented each time the boundary is updated in ArcGIS.',
    `centroid_latitude` DECIMAL(18,2) COMMENT 'GPS latitude coordinate of the field centroid in decimal degrees (WGS84), derived from RTK-accurate boundary geometry. Used for weather data integration, GIS spatial queries, and precision agriculture applications.',
    `centroid_longitude` DECIMAL(18,2) COMMENT 'GPS longitude coordinate of the field centroid in decimal degrees (WGS84), derived from RTK-accurate boundary geometry. Used for weather data integration, GIS spatial queries, and precision agriculture applications.',
    `conservation_practice_code` STRING COMMENT 'USDA NRCS conservation practice standard code (e.g., 340 Cover Crop, 412 Grassed Waterway) applied to the field. Supports BMP (Best Management Practices) compliance tracking, EQIP program reporting, and ISO 14001 environmental management.',
    `country_code` STRING COMMENT 'Three-letter ISO 3166-1 alpha-3 country code for the country in which the field is located. Supports international operations, COOL (Country of Origin Labeling) compliance, and multi-jurisdiction regulatory reporting.. Valid values are `^[A-Z]{3}$`',
    `county_name` STRING COMMENT 'Name of the county or administrative district in which the field is located. Used for USDA FSA county office routing, state regulatory reporting, and geographic aggregation in analytics.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when the field record was first created in the system, in ISO 8601 format (yyyy-MM-ddTHH:mm:ss.SSSXXX). Used for data lineage, audit trail, and FSMA traceability compliance.',
    `drainage_class` STRING COMMENT 'USDA NRCS standard drainage class describing the natural drainage condition of the fields dominant soil. Drives tile drainage planning, irrigation scheduling, and BMP selection. [ENUM-REF-CANDIDATE: excessively_drained|well_drained|moderately_well_drained|somewhat_poorly_drained|poorly_drained|very_poorly_drained — promote to reference product]. Valid values are `excessively_drained|well_drained|moderately_well_drained|somewhat_poorly_drained|poorly_drained|very_poorly_drained`',
    `elevation_m` DECIMAL(18,2) COMMENT 'Mean elevation of the field above sea level in metres, derived from digital elevation model (DEM) data in Esri ArcGIS. Used for frost risk assessment, drainage planning, and microclimate modelling.',
    `field_code` STRING COMMENT 'Externally-known alphanumeric business identifier for the field, used in operational systems such as John Deere Operations Center, Trimble Ag Software, and SAP S/4HANA PP module for field-level planning and task assignment.. Valid values are `^[A-Z0-9_-]{2,30}$`',
    `field_name` STRING COMMENT 'Human-readable name assigned to the field or paddock by the farm operator, used for identification in farm management information systems (FMIS), field maps, and operational communications.',
    `field_status` STRING COMMENT 'Current operational lifecycle status of the field. active indicates the field is in production; fallow indicates a rest period; retired indicates the field is no longer in use; quarantine indicates a regulatory hold; conservation indicates enrollment in a conservation program such as CRP.. Valid values are `active|fallow|retired|quarantine|conservation`',
    `field_type` STRING COMMENT 'Classification of the field by its primary agricultural use type. Drives applicable crop planning, irrigation, and compliance workflows. [ENUM-REF-CANDIDATE: cropland|pasture|orchard|vineyard|greenhouse|paddock|wetland|woodland — promote to reference product]',
    `fsa_field_number` STRING COMMENT 'USDA Farm Service Agency (FSA) assigned field number within the tract, uniquely identifying the field for federal acreage reporting, crop insurance, and USDA program compliance.',
    `fsa_tract_number` STRING COMMENT 'USDA Farm Service Agency (FSA) assigned tract number for the field, used for federal program enrollment, acreage reporting, and crop insurance compliance. Required for USDA commodity program participation.',
    `gmo_restricted` BOOLEAN COMMENT 'Indicates whether the field is designated as GMO-restricted, prohibiting the planting of genetically modified organism (GMO) seed varieties. Supports identity preservation (IP) programs and non-GMO supply chain segregation.',
    `irrigated_area_ha` DECIMAL(18,2) COMMENT 'Area of the field that is equipped and actively managed for irrigation, measured in hectares. Used for water resource management planning, evapotranspiration (ET) calculations, and irrigation scheduling.',
    `irrigation_system_type` STRING COMMENT 'Type of irrigation infrastructure installed on the field. Drives irrigation scheduling, water use efficiency calculations, and evapotranspiration (ET)-based management in Trimble Ag Software and Climate FieldView.. Valid values are `center_pivot|drip|flood|sprinkler|subsurface_drip|none`',
    `jd_ops_field_code` STRING COMMENT 'External integration key referencing the field record in John Deere Operations Center (precision agriculture and fleet telematics platform). Enables cross-system field-level data linkage for planting, spraying, and harvest operations.',
    `land_use_code` STRING COMMENT 'Standardized land use classification code assigned to the field per USDA NASS or local regulatory authority (e.g., USDA CLU land use code). Used for regulatory reporting, conservation program eligibility, and GIS land use mapping.',
    `lease_rate_per_ha` DECIMAL(18,2) COMMENT 'Annual cash rent or equivalent lease cost per hectare for this field, used in land cost budgeting, COGS (Cost of Goods Sold) allocation, and ROI (Return on Investment) analysis in Granular Farm Management and SAP CO.',
    `lease_type` STRING COMMENT 'Classification of the land tenure arrangement for this field. Drives financial planning in Granular Farm Management, land cost allocation in SAP CO, and lease obligation reporting under IFRS 16.. Valid values are `owned|cash_rent|crop_share|custom_farm|public_land`',
    `ndvi_last_score` DECIMAL(18,2) COMMENT 'Most recent NDVI (Normalized Difference Vegetation Index) score for the field, ranging from -1.0 to 1.0, derived from satellite or drone imagery. Used for crop health monitoring, yield forecasting, and VRA prescription generation.',
    `ndvi_observation_date` DATE COMMENT 'Date on which the most recent NDVI score was captured via satellite or drone imagery. Used to assess the currency of vegetation health data for crop scouting and agronomic decision-making.',
    `slope_percent` DECIMAL(18,2) COMMENT 'Average slope of the field expressed as a percentage (rise over run × 100). Used for erosion risk assessment, irrigation design, machinery safety planning, and BMP (Best Management Practices) compliance.',
    `soil_series_name` STRING COMMENT 'USDA NRCS official soil series name for the dominant soil type in the field (e.g., Drummer, Tama, Clarion). Used for soil health benchmarking, input rate calibration, and agronomic planning.',
    `soil_texture_class` STRING COMMENT 'USDA soil texture classification for the dominant topsoil horizon, describing the relative proportions of sand, silt, and clay. Influences water-holding capacity, tillage timing, and fertilizer application rates. [ENUM-REF-CANDIDATE: sand|loamy_sand|sandy_loam|loam|silt_loam|silt|clay_loam|silty_clay_loam|sandy_clay|silty_clay|clay — promote to reference product]',
    `state_province_code` STRING COMMENT 'Two- or three-letter ISO 3166-2 state or province code where the field is located. Used for regulatory jurisdiction routing, state-level compliance reporting, and geographic segmentation.. Valid values are `^[A-Z]{2,3}$`',
    `total_area_ha` DECIMAL(18,2) COMMENT 'Total gross area of the field measured in hectares, derived from RTK-accurate GIS boundary geometry in Esri ArcGIS. Used for yield-per-acre metric (YPM) calculations, input rate planning, and FSA acreage reporting.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent update to the field record, in ISO 8601 format (yyyy-MM-ddTHH:mm:ss.SSSXXX). Used for change data capture (CDC), data lineage, and audit trail in the Databricks lakehouse silver layer.',
    `vra_zone_count` STRING COMMENT 'Number of sub-field management zones delineated within this field for variable rate application (VRA) prescriptions, based on EC (Electrical Conductivity), yield history, and NDVI (Normalized Difference Vegetation Index) data. Supports precision agriculture planning in Trimble Ag Software.',
    CONSTRAINT pk_field PRIMARY KEY(`field_id`)
) COMMENT 'Master record for each agricultural field or paddock — the foundational spatial and operational entity of the land domain. Captures RTK-accurate GIS boundary geometry (polygon/multipolygon from Esri ArcGIS) with versioned boundary history, field name, code, total area, irrigated area, GPS centroid, elevation, slope, aspect, drainage class, status (active/fallow/retired), sub-field management zones (VRA zones delineated by EC/yield/NDVI), and integration keys to John Deere Operations Center and ArcGIS feature IDs. Supports boundary change tracking for FSA compliance and temporal field geometry. SSOT for all field-level spatial identity, boundary history, and precision management zone definitions.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`land`.`parcel` (
    `parcel_id` BIGINT COMMENT 'Unique surrogate identifier for the legal land parcel record in the enterprise data platform (Silver Layer primary key).',
    `farm_unit_id` BIGINT COMMENT 'Reference to the operational farm unit to which this parcel is administratively assigned for crop planning, workforce, and equipment management.',
    `acquisition_cost` DECIMAL(18,2) COMMENT 'Total purchase price or capitalized cost at which the enterprise acquired fee-simple title to the parcel, recorded in USD for fixed asset accounting, CAPEX tracking, and land valuation analysis.',
    `acquisition_date` DATE COMMENT 'Date the enterprise acquired operational control of the parcel (purchase closing date for owned parcels, lease commencement date for leased parcels), used for depreciation schedules, lease accounting (ASC 842), and tenure analysis.',
    `annual_property_tax` DECIMAL(18,2) COMMENT 'Most recent annual property tax levy assessed by the county on this parcel in USD, used for OPEX budgeting, land cost-per-acre analysis, and financial planning in Granular Farm Management.',
    `apn` STRING COMMENT 'County assessor-assigned Assessor Parcel Number (APN) uniquely identifying the parcel within the county tax roll. Primary government-issued cadastral identifier used for title searches, deed recording, and property tax assessment.',
    `arcgis_layer_code` STRING COMMENT 'Unique feature identifier within the Esri ArcGIS parcel boundary layer, enabling direct linkage to the authoritative GIS polygon geometry for spatial analysis, field mapping, and environmental monitoring.',
    `assessed_value` DECIMAL(18,2) COMMENT 'County assessors most recent assessed market value of the parcel in USD, used for property tax calculation, financial reporting, and land portfolio valuation.',
    `centroid_latitude` DECIMAL(18,2) COMMENT 'WGS84 decimal-degree latitude of the parcel centroid as derived from Esri ArcGIS or John Deere Operations Center RTK-accurate field mapping, used for geospatial analysis, weather data correlation, and GIS integration.',
    `centroid_longitude` DECIMAL(18,2) COMMENT 'WGS84 decimal-degree longitude of the parcel centroid as derived from Esri ArcGIS or John Deere Operations Center RTK-accurate field mapping, used for geospatial analysis, weather data correlation, and GIS integration.',
    `clu_identifier` STRING COMMENT 'USDA FSA Common Land Unit (CLU) identifier — the smallest unit of land with a permanent, contiguous boundary used for farm program administration, acreage determination, and geospatial analysis.',
    `conservation_program_enrollment` STRING COMMENT 'USDA conservation program in which this parcel is currently enrolled (e.g., Conservation Reserve Program (CRP), Environmental Quality Incentives Program (EQIP), Conservation Stewardship Program (CSP)), affecting land use restrictions and payment eligibility.. Valid values are `CRP|EQIP|CSP|ACEP|WRP|none`',
    `country_code` STRING COMMENT 'ISO 3166-1 alpha-3 three-letter country code for the country in which the parcel is located, supporting international operations and Country of Origin Labeling (COOL) compliance.. Valid values are `^[A-Z]{3}$`',
    `county` STRING COMMENT 'Name of the county in which the parcel is physically located, used for tax jurisdiction, FSA county office assignment, regulatory compliance, and geospatial reporting.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when the parcel record was first created in the enterprise data platform, used for data lineage, audit trail, and Silver Layer ingestion tracking.',
    `deed_book` STRING COMMENT 'County recorder deed book reference (book number or volume) where the current title instrument for this parcel is recorded, supporting title chain verification and encumbrance searches.',
    `deed_page` STRING COMMENT 'County recorder deed page reference within the deed book where the current title instrument is recorded, used in conjunction with deed_book for precise title document retrieval.',
    `deed_recording_date` DATE COMMENT 'Date the current deed or title instrument was officially recorded with the county recorder, establishing the effective date of ownership transfer and priority in the title chain.',
    `flood_zone_designation` STRING COMMENT 'FEMA National Flood Insurance Program (NFIP) flood zone designation for the parcel, used for crop insurance underwriting, lender requirements, conservation planning, and drainage infrastructure investment decisions.. Valid values are `Zone A|Zone AE|Zone X|Zone X500|Zone V|Zone D`',
    `fsa_cropland_acres` DECIMAL(18,2) COMMENT 'USDA FSA-determined cropland acres within the parcel eligible for commodity program enrollment, ARC/PLC payments, and conservation program base acre calculations.',
    `fsa_farm_number` STRING COMMENT 'USDA Farm Service Agency (FSA) assigned farm number linking this parcel to the FSA farm record for program eligibility, commodity reporting, and conservation compliance.',
    `fsa_tract_number` STRING COMMENT 'USDA FSA tract number subdividing the FSA farm into contiguous land units under common ownership or control, used for acreage reporting and program payment calculations.',
    `irrigated_acres` DECIMAL(18,2) COMMENT 'Total acres within the parcel served by an irrigation system (surface, drip, pivot, or flood), used for water right allocation, irrigation scheduling, and USDA program reporting.',
    `land_use_designation` STRING COMMENT 'Primary land use classification for the parcel as designated by the county assessor or USDA FSA, determining eligible farm programs, conservation requirements, and operational planning. [ENUM-REF-CANDIDATE: cropland|pasture|rangeland|woodland|wetland|farmstead|idle|conservation|orchard|vineyard|fallow — promote to reference product]',
    `legal_description` STRING COMMENT 'Full legal description of the parcel as recorded in the county deed or land registry, including metes-and-bounds, lot-block-subdivision, or Public Land Survey System (PLSS) section-township-range narrative.',
    `nrcs_land_capability_class` STRING COMMENT 'USDA Natural Resources Conservation Service (NRCS) land capability class (I–VIII) and subclass (e, w, s, c) rating the parcels suitability for cultivation, indicating erosion risk, drainage limitations, and conservation treatment needs.. Valid values are `^[I]{1,3}V?[a-z]?$`',
    `organic_certification_status` STRING COMMENT 'Current USDA National Organic Program (NOP) certification status of the parcel, indicating whether the land meets organic production requirements, is in the 3-year transition period, or is managed under conventional practices.. Valid values are `certified|transitioning|conventional|exempt`',
    `organic_transition_start_date` DATE COMMENT 'Date on which the parcel began the USDA NOP-required 36-month transition period from conventional to certified organic production, used to track certification eligibility and compliance timelines.',
    `ownership_type` STRING COMMENT 'Classification of the operational control arrangement for this parcel — whether the enterprise holds fee-simple title (owned), operates under a cash rent lease, crop-share lease, or custom farming agreement.. Valid values are `owned|leased|cash_rent|crop_share|custom_farmed`',
    `parcel_name` STRING COMMENT 'Operational or colloquial name assigned to the parcel by the farm operation (e.g., North Quarter, River Bottom Field) for internal identification and communication.',
    `parcel_status` STRING COMMENT 'Current lifecycle status of the parcel record indicating its operational and administrative state within the enterprise land management system.. Valid values are `active|inactive|pending|encumbered|retired`',
    `plss_range` STRING COMMENT 'Range designation (e.g., R5E) within the PLSS grid, representing the east-west position relative to a principal meridian.',
    `plss_section` STRING COMMENT 'Section number (1–36) within the Public Land Survey System (PLSS) township-range grid identifying the one-square-mile land division containing this parcel.. Valid values are `^[0-9]{1,2}$`',
    `plss_township` STRING COMMENT 'Township designation (e.g., T12N) within the PLSS grid, representing the north-south position relative to a principal meridian baseline.',
    `prime_farmland_class` STRING COMMENT 'USDA NRCS prime farmland classification indicating the lands capability for sustained agricultural production, used for conservation program eligibility (ACEP, RCPP), environmental impact assessments, and land use planning.. Valid values are `prime|statewide_importance|unique|not_prime`',
    `soil_survey_map_unit` STRING COMMENT 'USDA NRCS Web Soil Survey map unit symbol (e.g., HrA, MnB2) identifying the dominant soil series and slope class for the parcel, used for soil health planning, conservation program eligibility, and variable rate application (VRA) prescriptions.',
    `state_code` STRING COMMENT 'Two-letter USPS state abbreviation for the state in which the parcel is located, used for regulatory jurisdiction, FSA state office routing, and geospatial classification.. Valid values are `^[A-Z]{2}$`',
    `total_deeded_acres` DECIMAL(18,2) COMMENT 'Total land area of the parcel as recorded in the county deed or land registry, expressed in acres. Represents the legal boundary area and is the authoritative acreage for title, tax assessment, and FSA program enrollment.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent update to the parcel record in the enterprise data platform, supporting change data capture (CDC), audit compliance, and data freshness monitoring.',
    `wetland_indicator` BOOLEAN COMMENT 'Flag indicating whether any portion of the parcel contains USDA NRCS-delineated wetlands subject to Swampbuster provisions (Food Security Act), EPA Section 404 permitting, and conservation program restrictions.',
    `zoning_classification` STRING COMMENT 'County or municipal zoning designation for the parcel (e.g., A-1 Agricultural, A-2 Rural Residential, EFU Exclusive Farm Use) governing permitted land uses, structure placement, and development rights.',
    CONSTRAINT pk_parcel PRIMARY KEY(`parcel_id`)
) COMMENT 'Legal land parcel (cadastral unit) as defined by county assessor or land registry records. Stores APN (Assessor Parcel Number), legal description, section-township-range (PLSS), county, state, country, total deeded acres, zoning classification, land use designation, FSA farm/tract number, CLU (Common Land Unit) identifier, and USDA FSA administrative data. One parcel may contain multiple fields and belongs to a farm_unit for operational management. Links to land_ownership for title chain, to lease for tenant agreements, to easement for encumbrances, and to water_right for entitlement tracking. SSOT for legal land identity and government-assigned identifiers.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`land`.`ownership` (
    `ownership_id` BIGINT COMMENT 'Unique surrogate identifier for each land ownership record in the system. Primary key for the land_ownership data product.',
    `account_id` BIGINT COMMENT 'Reference to the legal owner party (individual, entity, trust, LLC, or partnership) holding an ownership interest in this parcel.',
    `parcel_id` BIGINT COMMENT 'Reference to the land parcel that is subject to this ownership record. Links to the parcel master record in the land domain.',
    `prior_ownership_id` BIGINT COMMENT 'Self-referencing identifier pointing to the immediately preceding ownership record in the chain of title for this parcel. Enables traversal of the full ownership history and chain-of-title lineage.',
    `assessor_parcel_number` STRING COMMENT 'The Assessor Parcel Number (APN) assigned by the county assessors office for property tax assessment purposes. Also known as a parcel identification number (PIN) or tax parcel number. Used for cross-referencing with county tax records.',
    `chain_sequence` STRING COMMENT 'Sequential integer indicating the position of this ownership record in the chain of title for the parcel. A value of 1 represents the earliest recorded ownership; higher values represent more recent ownership records. Supports chain-of-title history and ownership lineage analysis.',
    `conservation_easement_flag` BOOLEAN COMMENT 'Indicates whether this parcel is subject to a conservation easement that restricts certain land uses in perpetuity or for a defined term. Conservation easements are commonly held by land trusts or government agencies under USDA NRCS programs.',
    `conveyance_date` DATE COMMENT 'The date on which the ownership interest was conveyed (transferred) from the prior owner to the current owner, as stated in the deed instrument. Distinct from recording_date (when filed) and effective_date (when legally binding).',
    `country_code` STRING COMMENT 'Three-letter ISO 3166-1 alpha-3 country code for the country in which the parcel is located. Supports international operations and COOL (Country of Origin Labeling) compliance.. Valid values are `^[A-Z]{3}$`',
    `county_name` STRING COMMENT 'Name of the county in which the parcel is located and where the deed is recorded. Used for jurisdictional routing of legal documents and regulatory reporting to USDA FSA county offices.',
    `created_timestamp` TIMESTAMP COMMENT 'The timestamp when this ownership record was first created in the system. Supports audit trail, data lineage, and compliance with FSMA record-keeping requirements.',
    `data_quality_flag` STRING COMMENT 'Indicates the data quality and verification status of this ownership record. Verified means the record has been validated against official county recorder or title company sources; unverified means the record has not yet been validated; under_review means validation is in progress; rejected means the record failed validation.. Valid values are `verified|unverified|under_review|rejected`',
    `deed_book` STRING COMMENT 'The deed book (volume) number in the county recorders office where the deed instrument is officially recorded. Used in conjunction with deed_page for precise legal document retrieval.',
    `deed_instrument_type` STRING COMMENT 'Classification of the legal deed instrument used to convey ownership. Warranty deeds provide full title guarantees; quitclaim deeds convey only the grantors existing interest; grant deeds include implied warranties; trustee and sheriff deeds arise from trust or court proceedings.. Valid values are `warranty_deed|quitclaim_deed|grant_deed|special_warranty_deed|trustee_deed|sheriff_deed`',
    `deed_page` STRING COMMENT 'The page number within the deed book at the county recorders office where the deed instrument is officially recorded. Used in conjunction with deed_book for precise legal document retrieval.',
    `deed_reference_number` STRING COMMENT 'Unique reference number assigned to the deed instrument conveying ownership of this parcel. Used to cross-reference with county recorder and title company records for chain-of-title verification.',
    `dispute_notes` STRING COMMENT 'Free-text notes describing the nature of any ownership dispute, legal challenge, or title defect associated with this ownership record. Populated when ownership_status is disputed. Supports legal team review and resolution tracking.',
    `effective_date` DATE COMMENT 'The date on which the ownership interest legally became effective, which may differ from the recording date. For example, a deed may be executed and effective on one date but recorded later. This is the MASTER_AGREEMENT EFFECTIVE_FROM field for this ownership record.',
    `encumbrance_description` STRING COMMENT 'Narrative description of any encumbrances, liens, easements, mortgages, conservation easements, or other title restrictions affecting this ownership record. Populated when encumbrance_flag is True.',
    `encumbrance_flag` BOOLEAN COMMENT 'Indicates whether this ownership record is subject to any encumbrances, liens, easements, mortgages, or other claims against the title that may affect the owners full use and enjoyment of the parcel.',
    `expiration_date` DATE COMMENT 'The date on which the ownership interest expires or terminates, applicable for term interests such as life estates or time-limited ownership arrangements. Null for perpetual fee simple ownership. This is the MASTER_AGREEMENT EFFECTIVE_UNTIL field.',
    `farm_service_agency_tract_number` STRING COMMENT 'The USDA Farm Service Agency (FSA) tract number assigned to this parcel for farm program eligibility, commodity program enrollment, and conservation program participation tracking.',
    `legal_description` STRING COMMENT 'Full legal description of the parcel as recorded on the deed, typically expressed in metes and bounds, Public Land Survey System (PLSS) section-township-range notation, or lot-block-subdivision format. This is the authoritative legal boundary description for the parcel.',
    `notes` STRING COMMENT 'General free-text notes or remarks related to this ownership record, including special conditions, legal caveats, or administrative observations not captured in structured fields.',
    `owner_entity_type` STRING COMMENT 'Classification of the legal entity type of the owner. Distinguishes between natural persons and legal entities for regulatory reporting, USDA farm program eligibility, and compliance with FSMA and COOL requirements. [ENUM-REF-CANDIDATE: individual|corporation|llc|partnership|trust|government|cooperative|nonprofit — promote to reference product]',
    `ownership_status` STRING COMMENT 'Current lifecycle state of this ownership record. Current indicates active legal ownership; historical indicates a past ownership interest that has been transferred or extinguished; disputed flags records under legal challenge; pending indicates a transfer in progress; transferred indicates completed conveyance to a new owner.. Valid values are `current|historical|disputed|pending|transferred`',
    `ownership_type` STRING COMMENT 'Legal classification of the ownership interest held by the owner in this parcel. Fee simple is the most complete form of ownership; joint tenancy includes right of survivorship; tenancy in common allows fractional interests without survivorship; life estate is limited to the owners lifetime; trust and LLC membership reflect entity-held interests.. Valid values are `fee_simple|joint_tenancy|tenancy_in_common|life_estate|trust|llc_membership`',
    `percentage` DECIMAL(18,2) COMMENT 'Fractional ownership interest held by this owner in the parcel, expressed as a percentage (e.g., 50.0000 for a 50% undivided interest). Supports multi-owner parcels with tenancy-in-common or LLC membership fractional interest tracking. All ownership records for a parcel should sum to 100%.',
    `record_number` STRING COMMENT 'Externally-known unique reference number assigned to this ownership record, used for cross-referencing with county recorder offices, title companies, and legal documentation. Serves as the business identifier for chain-of-title tracking.',
    `recording_date` DATE COMMENT 'The date on which the deed or ownership instrument was officially recorded with the county recorders office. Establishes the legal priority of the ownership claim in the chain of title.',
    `source_system` STRING COMMENT 'Identifies the operational system of record from which this ownership record was sourced or last updated. Supports data lineage and master data management. Typical sources include Granular Farm Management, Esri ArcGIS, SAP S/4HANA, Oracle NetSuite, or manual entry.. Valid values are `granular|arcgis|sap_s4hana|netsuite|manual`',
    `state_code` STRING COMMENT 'Two-letter USPS state abbreviation for the state in which the parcel is located. Used for jurisdictional compliance, USDA FSA state office routing, and regulatory reporting.. Valid values are `^[A-Z]{2}$`',
    `title_insurance_company` STRING COMMENT 'Name of the title insurance underwriter or company that issued the title insurance policy for this ownership record. Used for claims processing and title defect resolution.',
    `title_insurance_policy_number` STRING COMMENT 'The policy number of the title insurance policy issued to protect the owners interest in this parcel against title defects, liens, or encumbrances not discovered during the title search. Issued by a licensed title insurance underwriter.',
    `transfer_reason` STRING COMMENT 'The reason or mechanism by which ownership was transferred to the current owner. Used for USDA FSA farm program eligibility determination, estate planning analysis, and land tenure reporting. [ENUM-REF-CANDIDATE: sale|inheritance|gift|foreclosure|condemnation|partition|exchange|court_order — promote to reference product]',
    `updated_timestamp` TIMESTAMP COMMENT 'The timestamp when this ownership record was last modified in the system. Supports audit trail, change tracking, and data lineage for compliance with SOX and FSMA record-keeping requirements.',
    `usda_farm_number` STRING COMMENT 'The USDA Farm Service Agency (FSA) farm number associated with this parcel, used for enrollment in commodity support programs, conservation programs, and crop insurance. A single farm number may encompass multiple tracts and parcels.',
    CONSTRAINT pk_ownership PRIMARY KEY(`ownership_id`)
) COMMENT 'Ownership record linking parcels to legal owners (individuals, entities, trusts, LLCs, partnerships). Captures owner name, ownership type (fee simple, joint tenancy, tenancy in common, life estate, trust, LLC membership), ownership percentage share, deed reference number, deed book and page, recording date, effective date, expiration date (for term interests), title insurance policy number, and ownership status (current/historical/disputed). Supports multi-owner parcels with fractional interest tracking and ownership chain history. Note: land valuation and acquisition financial transactions are owned by the finance domain — this product captures legal ownership records only. SSOT for who legally owns each parcel and the chain of title.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`land`.`lease` (
    `lease_id` BIGINT COMMENT 'Unique system-generated identifier for the agricultural land lease agreement record. Primary key for the lease data product.',
    `contact_id` BIGINT COMMENT 'Reference to the landowner (lessor) party record. Identifies the individual or entity that owns the land and is granting the lease.',
    `farm_unit_id` BIGINT COMMENT 'Reference to the operational farm unit to which the leased land is assigned. Provides operational context for crop planning and field operations.',
    `parcel_id` BIGINT COMMENT 'Reference to the land parcel(s) covered under this lease agreement. Links to the parcel master record in the land domain for legal and GIS boundary context.',
    `account_id` BIGINT COMMENT 'Foreign key linking to customer.account. Business justification: Leases are executed between legal entities (accounts). The tenant operator account is required for billing, FSA farm operator designation, crop insurance enrollment, and lease payment processing. Role',
    `auto_renewal_flag` BOOLEAN COMMENT 'Indicates whether the lease agreement contains an automatic renewal clause. When True, the lease renews for an additional term at expiry unless either party provides written notice of termination within the required notice period.',
    `cash_rent_rate_per_acre` DECIMAL(18,2) COMMENT 'Annual cash rent rate expressed in US dollars per acre. Applicable for cash_rent and flex_rent lease types. Represents the base rental obligation per acre per year. Sensitive commercial term.',
    `conservation_practice_required_flag` BOOLEAN COMMENT 'Indicates whether the lease agreement mandates adherence to specific conservation practices (e.g., cover cropping, no-till, buffer strips) as a condition of tenancy. Supports BMP and ISO 14001 environmental compliance tracking.',
    `county_fips_code` STRING COMMENT 'Five-digit FIPS code identifying the US county in which the leased land is located. Used for USDA program enrollment, regulatory reporting, and geographic analytics.. Valid values are `^[0-9]{5}$`',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when the lease record was first created in the system. Supports audit trail, data lineage, and Silver layer ingestion tracking. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `crop_restriction` STRING COMMENT 'Free-text description of any crop-specific restrictions or requirements stipulated in the lease (e.g., no GMO crops, organic production required, specific rotation mandated). Impacts crop planning and seed selection decisions.',
    `crop_share_percentage` DECIMAL(18,2) COMMENT 'Percentage of crop proceeds or harvested commodity allocated to the landowner under a crop share lease arrangement. Typically ranges from 25% to 50%. Applicable only when lease_type is crop_share.',
    `currency_code` STRING COMMENT 'Three-letter ISO 4217 currency code for all monetary amounts in this lease record (e.g., USD, CAD, BRL). Supports international operations and multi-currency reporting.. Valid values are `^[A-Z]{3}$`',
    `document_reference` STRING COMMENT 'Reference identifier or URL to the executed lease agreement document stored in the document management system. Enables retrieval of the original signed contract for legal and audit purposes.',
    `end_date` DATE COMMENT 'The date on which the lease agreement expires or is scheduled to terminate. Nullable for open-ended or evergreen leases. Used for renewal planning and land tenure reporting.',
    `execution_date` DATE COMMENT 'The date on which the lease agreement was formally signed and executed by both parties. May differ from the start date for leases signed in advance of the crop year.',
    `flex_rent_base_price` DECIMAL(18,2) COMMENT 'The commodity base price (in $/bushel or $/MT) used as the reference point for flex rent adjustment calculations. When the actual commodity price exceeds this threshold, additional rent is triggered. Applicable only for flex_rent lease type.',
    `flex_rent_cap_per_acre` DECIMAL(18,2) COMMENT 'Maximum allowable flex rent payment per acre per year, capping the upside obligation for the tenant regardless of commodity price or yield performance. Applicable only for flex_rent lease type.',
    `flex_rent_trigger_mechanism` STRING COMMENT 'The mechanism that activates the flex rent adjustment above the base cash rent. Price trigger: based on commodity market price. Yield trigger: based on actual field yield (YPM). Revenue trigger: based on gross revenue per acre. None: not applicable for non-flex leases.. Valid values are `price_trigger|yield_trigger|revenue_trigger|none`',
    `fsa_farm_number` STRING COMMENT 'USDA Farm Service Agency (FSA) assigned farm number for the leased land. Required for federal program enrollment, crop insurance, and USDA compliance reporting. Links to FSA farm records.. Valid values are `^[0-9]{7}$`',
    `fsa_tract_number` STRING COMMENT 'USDA FSA tract number identifying the specific tract of land within the FSA farm record. A farm may contain multiple tracts; this field identifies the specific tract(s) covered by this lease.',
    `improvements_allowed_flag` BOOLEAN COMMENT 'Indicates whether the lease agreement permits the tenant to make permanent improvements to the land (e.g., drainage tile installation, building construction, irrigation infrastructure). Relevant for CAPEX planning and land stewardship.',
    `lease_number` STRING COMMENT 'Externally-known, human-readable business identifier for the lease agreement. Used in correspondence with landowners, FSA filings, and internal reference. Format: LSE-YYYY-NNNNNN.. Valid values are `^LSE-[0-9]{4}-[0-9]{6}$`',
    `lease_status` STRING COMMENT 'Current lifecycle state of the lease agreement. Active: in force and binding. Expired: past end date without renewal. Terminated: ended early by either party. Pending: executed but not yet effective. Under negotiation: terms being discussed. Draft: not yet executed.. Valid values are `active|expired|terminated|pending|under_negotiation|draft`',
    `lease_type` STRING COMMENT 'Classification of the lease agreement structure. Cash rent: fixed $/acre payment. Crop share: landlord receives a percentage of crop proceeds. Flex rent: base rent adjusted by commodity price or yield triggers. Custom farming: operator provides services for a fee. Pasture lease: grazing rights. Hunting lease: recreational use. [ENUM-REF-CANDIDATE: cash_rent|crop_share|flex_rent|custom_farming|pasture_lease|hunting_lease — promote to reference product]. Valid values are `cash_rent|crop_share|flex_rent|custom_farming|pasture_lease|hunting_lease`',
    `legal_description` STRING COMMENT 'Formal legal description of the leased land parcel(s) as recorded in the deed or title document. Typically expressed in Public Land Survey System (PLSS) notation (e.g., Section-Township-Range) or metes and bounds.',
    `notes` STRING COMMENT 'Free-text field for capturing additional terms, special conditions, negotiation history, or operational notes related to the lease agreement that are not captured in structured fields.',
    `payment_due_month` STRING COMMENT 'Calendar month (1–12) in which the primary annual rent payment is due to the landowner. For semi-annual schedules, this represents the first payment month. Used by the finance domain to schedule AP obligations.',
    `payment_schedule` STRING COMMENT 'Frequency at which cash rent payments are due to the landowner under the lease agreement. Drives accounts payable scheduling in the finance domain. Common agricultural practice is annual or semi-annual.. Valid values are `annual|semi_annual|quarterly|monthly`',
    `renewal_notice_days` STRING COMMENT 'Number of days prior to the lease end date by which written notice of non-renewal or termination must be provided by either party. Typically 30, 60, or 90 days for agricultural leases. Drives automated renewal alert workflows.',
    `right_of_first_refusal_flag` BOOLEAN COMMENT 'Indicates whether the lease agreement grants the tenant/operator a right of first refusal (ROFR) to purchase the land if the landowner decides to sell. When True, the operator must be offered the opportunity to match any third-party purchase offer.',
    `source_system` STRING COMMENT 'Identifies the operational system of record from which this lease record was ingested. Supports data lineage and reconciliation across Granular Farm Management, SAP RE-FX, and Oracle NetSuite.. Valid values are `granular|sap_re_fx|oracle_netsuite|manual_entry`',
    `start_date` DATE COMMENT 'The date on which the lease agreement becomes effective and the tenant/operator gains the right to use the land. Typically March 1 or the start of the crop year for agricultural leases.',
    `state_code` STRING COMMENT 'Two-letter US state abbreviation (or ISO 3166-2 subdivision code for international operations) identifying the state in which the leased land is located.. Valid values are `^[A-Z]{2}$`',
    `termination_date` DATE COMMENT 'The actual date on which the lease was terminated early, if applicable. Populated only when lease_status is terminated. Distinct from end_date which is the scheduled expiry.',
    `total_leased_acres` DECIMAL(18,2) COMMENT 'Total land area covered under this lease agreement, expressed in acres. Used for cash rent calculation, FSA reporting, and land tenure analytics. Sourced from FSA farm records or GIS boundary measurement.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent modification to the lease record. Used for change detection, incremental ETL processing, and audit compliance. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    CONSTRAINT pk_lease PRIMARY KEY(`lease_id`)
) COMMENT 'Agricultural land lease agreement record capturing the contractual relationship between landowner and farm operator/tenant for use of agricultural parcels. Stores lease type (cash rent, crop share, flex rent, custom farming agreement), lease start date, lease end date, annual cash rent rate ($/acre), crop share percentage, flex rent base price and trigger mechanism, total leased acres, payment schedule (annual/semi-annual/quarterly), auto-renewal flag, right-of-first-refusal flag, lease document reference, FSA farm number, and lease status (active/expired/terminated/pending/under negotiation). Links to parcel and farm_unit for legal and operational context. Note: lease payment transactions and accounts payable are owned by the finance/invoice domains — this product captures the lease agreement terms only, not financial transactions. SSOT for land tenure agreements and rental obligation terms.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`land`.`soil_profile` (
    `soil_profile_id` BIGINT COMMENT 'Unique system-generated identifier for the soil profile record. Primary key for the soil_profile data product within the land domain.',
    `field_id` BIGINT COMMENT 'Reference to the agricultural field or parcel to which this soil profile belongs. Links the soil profile to its geographic land unit as mapped in Esri ArcGIS and John Deere Operations Center.',
    `agronomist_notes` STRING COMMENT 'Free-text field for certified crop adviser (CCA) or agronomist observations about this soil profile, including anomalies, historical land use context, or special management considerations not captured in structured fields. Supports GLOBALG.A.P. and USDA NRCS conservation planning documentation.',
    `awc_cm_cm` DECIMAL(18,2) COMMENT 'Available Water Capacity (AWC) expressed as centimeters of water per centimeter of soil depth (cm/cm), representing the volume of water held between field capacity and permanent wilting point. Critical input for irrigation scheduling and evapotranspiration (ET) modeling.',
    `bulk_density_g_cm3` DECIMAL(18,2) COMMENT 'Soil bulk density expressed in grams per cubic centimeter (g/cm³), representing the mass of dry soil per unit volume including pore space. Indicates soil compaction level; values above 1.6 g/cm³ typically restrict root growth. Informs tillage and cover crop decisions.',
    `cec_meq_100g` DECIMAL(18,2) COMMENT 'Cation Exchange Capacity (CEC) expressed in milliequivalents per 100 grams of soil (meq/100g). Measures the soils ability to hold and supply positively charged nutrient ions (Ca, Mg, K, Na). Higher CEC indicates greater nutrient-holding capacity and influences fertilizer recommendations.',
    `conservation_practice_code` STRING COMMENT 'USDA NRCS Conservation Practice Standard code(s) applied to this soil mapping unit (e.g., 340 Cover Crop, 600 Terrace, 412 Grassed Waterway). Supports EQIP/CSP program documentation, BMP compliance reporting, and ISO 14001 environmental management system records.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this soil profile record was first created in the system, in ISO 8601 format (yyyy-MM-ddTHH:mm:ss.SSSXXX). Supports data lineage, audit trail, and FSMA traceability requirements.',
    `depth_to_restrictive_layer_cm` DECIMAL(18,2) COMMENT 'Depth in centimeters from the soil surface to the first restrictive layer (e.g., fragipan, claypan, bedrock, seasonal high water table). Limits effective rooting depth and influences crop selection, drainage tile placement, and irrigation design.',
    `drainage_class` STRING COMMENT 'USDA NRCS drainage class describing the natural soil drainage condition (e.g., well drained, poorly drained). Critical for tile drainage design, planting date decisions, and ISO 14001 environmental management. [ENUM-REF-CANDIDATE: excessively drained|somewhat excessively drained|well drained|moderately well drained|somewhat poorly drained|poorly drained|very poorly drained — promote to reference product]',
    `ec_ds_m` DECIMAL(18,2) COMMENT 'Soil electrical conductivity (EC) measured in deciSiemens per meter (dS/m), indicating soil salinity level. Values above 4 dS/m may indicate salinity stress for most crops. Used for precision agriculture zone delineation and irrigation water quality management.',
    `erosion_risk_class` STRING COMMENT 'Qualitative erosion risk classification for this soil profile based on USDA NRCS Universal Soil Loss Equation (USLE/RUSLE) factors including erodibility (K-factor), slope, and cover. Drives conservation practice selection and FSMA Produce Safety Rule compliance for water quality.. Valid values are `very low|low|moderate|high|very high`',
    `gis_map_unit_area_ha` DECIMAL(18,2) COMMENT 'Area of the soil mapping unit or management zone in hectares as calculated from the GIS polygon in Esri ArcGIS. Used for proportional nutrient application calculations, yield per acre metric (YPM) normalization, and land valuation.',
    `is_hydric` BOOLEAN COMMENT 'Boolean flag indicating whether this soil is classified as a hydric soil by USDA NRCS criteria, meaning it formed under conditions of saturation, flooding, or ponding long enough to develop anaerobic conditions. Hydric soils are associated with wetlands and trigger regulatory review under Section 404 of the Clean Water Act and USDA NRCS wetland conservation provisions.',
    `is_prime_farmland` BOOLEAN COMMENT 'Boolean flag indicating whether this soil mapping unit is designated as Prime Farmland, Farmland of Statewide Importance, or Unique Farmland by USDA NRCS. Prime farmland designation affects land use planning, conservation program eligibility (CRP, EQIP), and regulatory review for development.',
    `k_factor` DECIMAL(18,2) COMMENT 'USDA NRCS soil erodibility K-factor from the Universal Soil Loss Equation (USLE/RUSLE), ranging from 0.02 (least erodible) to 0.69 (most erodible). Quantifies the susceptibility of soil to detachment and transport by rainfall and runoff. Used in conservation planning and NRCS EQIP program applications.',
    `lab_reference_number` STRING COMMENT 'External laboratory sample reference or accession number assigned by the certified soil testing laboratory. Enables traceability back to the original Certificate of Analysis (COA) and laboratory report for audit and GLOBALG.A.P. compliance verification.',
    `land_capability_class` STRING COMMENT 'USDA NRCS Land Capability Classification (LCC) rating from Class I (fewest limitations) to Class VIII (unsuitable for cultivation). Used for conservation planning, crop insurance rating, and USDA program eligibility determination. [ENUM-REF-CANDIDATE: I|II|III|IV|V|VI|VII|VIII — 8 candidates stripped; promote to reference product]',
    `land_capability_subclass` STRING COMMENT 'USDA NRCS Land Capability Subclass modifier indicating the primary limitation type: e (erosion), w (wetness/drainage), s (soil limitations), c (climate). Complements the land_capability_class for conservation practice planning under BMP guidelines.. Valid values are `e|w|s|c`',
    `management_zone` STRING COMMENT 'Agronomic management zone designation within the field (e.g., Zone 1 - High Productivity, Zone 3 - Low OM). Used for variable rate application (VRA) prescriptions in Trimble Ag Software and Climate FieldView to optimize input use efficiency.',
    `mukey` STRING COMMENT 'USDA NRCS SSURGO (Soil Survey Geographic Database) Map Unit Key (MUKEY) — the unique national identifier for the soil map unit polygon. Enables direct linkage to the SSURGO database for detailed soil property lookup, Web Soil Survey integration, and NRCS program eligibility verification.. Valid values are `^[0-9]{1,10}$`',
    `nitrogen_ppm` DECIMAL(18,2) COMMENT 'Plant-available nitrogen (N) concentration in the soil expressed in parts per million (ppm), typically measured as nitrate-N or ammonium-N. Core component of NPK (Nitrogen-Phosphorus-Potassium) soil fertility assessment driving fertilization event planning.',
    `nrcs_soil_series` STRING COMMENT 'Official USDA NRCS soil series name assigned to this mapping unit (e.g., Drummer, Tama, Clarion). Derived from the SSURGO/Web Soil Survey database and used for agronomic benchmarking and land valuation.',
    `organic_matter_pct` DECIMAL(18,2) COMMENT 'Percentage of organic matter (OM) in the soil by weight, measured by loss-on-ignition or Walkley-Black method. Key indicator of soil health, water-holding capacity, and nutrient cycling. Supports carbon sequestration reporting and ISCC sustainability compliance.',
    `ph_method` STRING COMMENT 'Laboratory method used to determine the soil pH value (e.g., 1:1 water suspension, 1:2 CaCl2 solution). Required for accurate interpretation and cross-laboratory comparability of pH results per USDA NRCS and university extension standards.. Valid values are `1:1 water|1:2 CaCl2|saturated paste|buffer pH`',
    `ph_value` DECIMAL(18,2) COMMENT 'Soil pH (Potential of Hydrogen) measurement representing soil acidity or alkalinity on a 0–14 scale, typically measured in a 1:1 soil-water suspension. Drives lime application decisions, nutrient availability, and crop selection. Target range for most crops: 6.0–7.0.',
    `phosphorus_ppm` DECIMAL(18,2) COMMENT 'Plant-available phosphorus (P) concentration in the soil expressed in parts per million (ppm), typically measured by Bray-1, Mehlich-3, or Olsen extraction method. Core NPK component driving phosphate fertilizer recommendations and environmental runoff risk assessment.',
    `potassium_ppm` DECIMAL(18,2) COMMENT 'Plant-available potassium (K) concentration in the soil expressed in parts per million (ppm), typically measured by Mehlich-3 or ammonium acetate extraction. Core NPK component influencing crop quality, drought tolerance, and potash fertilizer application rates.',
    `profile_code` STRING COMMENT 'Externally-known alphanumeric code uniquely identifying this soil profile or management zone within the farm management information system (FMIS). Used for cross-referencing with Granular Farm Management and Trimble Ag Software records.. Valid values are `^[A-Z0-9_-]{3,30}$`',
    `profile_name` STRING COMMENT 'Human-readable descriptive name for the soil profile or management zone (e.g., North Field Zone A, River Bottom Unit 3). Used for display and reporting in FMIS dashboards.',
    `profile_status` STRING COMMENT 'Current lifecycle status of the soil profile record. active indicates the profile is the current SSOT for agronomic decisions; superseded indicates a newer profile has replaced it; pending_review indicates awaiting agronomist validation.. Valid values are `active|archived|pending_review|superseded`',
    `restrictive_layer_type` STRING COMMENT 'Classification of the soil restrictive layer type encountered at the depth recorded in depth_to_restrictive_layer_cm. Determines the agronomic and engineering implications for root penetration, drainage, and deep tillage feasibility. [ENUM-REF-CANDIDATE: fragipan|claypan|bedrock|hardpan|water table|caliche|permafrost — 7 candidates stripped; promote to reference product]',
    `sampling_date` DATE COMMENT 'Date on which the soil sample was collected for laboratory analysis that established or last updated this soil profile. Determines the currency of the soil data for agronomic decision-making; most university extension services recommend resampling every 3–4 years.',
    `sampling_depth_cm` DECIMAL(18,2) COMMENT 'Depth in centimeters at which the soil sample was collected (e.g., 0–15 cm for surface, 15–30 cm for subsoil). Sampling depth affects interpretation of pH, OM, and nutrient results and must be consistent across sampling events for trend analysis.',
    `slope_pct` DECIMAL(18,2) COMMENT 'Average slope of the soil mapping unit expressed as a percentage (rise/run × 100). Influences erosion risk assessment, tillage method selection, irrigation system design, and conservation practice requirements under USDA NRCS and EPA BMP guidelines.',
    `soil_order` STRING COMMENT 'Highest-level USDA Soil Taxonomy classification order for this soil profile (e.g., Mollisol, Alfisol). Determines broad agronomic suitability and management approach. [ENUM-REF-CANDIDATE: Alfisol|Andisol|Aridisol|Entisol|Gelisol|Histosol|Inceptisol|Mollisol|Oxisol|Spodosol|Ultisol|Vertisol — promote to reference product]',
    `soil_suborder` STRING COMMENT 'Second-level USDA Soil Taxonomy classification suborder for this soil profile (e.g., Udoll, Aquoll). Provides finer agronomic classification for crop suitability and drainage management planning.',
    `texture_class` STRING COMMENT 'USDA soil texture classification based on the relative proportions of sand, silt, and clay as determined by the USDA textural triangle. Drives irrigation scheduling, tillage decisions, and nutrient management planning. [ENUM-REF-CANDIDATE: sand|loamy sand|sandy loam|loam|silt loam|silt|sandy clay loam|clay loam|silty clay loam|sandy clay|silty clay|clay — promote to reference product]',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this soil profile record was most recently modified, in ISO 8601 format (yyyy-MM-ddTHH:mm:ss.SSSXXX). Tracks data currency for agronomic decision support and supports audit trail requirements under GLOBALG.A.P. and ISO 14001.',
    CONSTRAINT pk_soil_profile PRIMARY KEY(`soil_profile_id`)
) COMMENT 'Authoritative soil health profile for a defined soil mapping unit or management zone within a field. Stores USDA NRCS soil series name, soil texture class (USDA triangle), soil order/suborder, drainage class, available water capacity (AWC), organic matter percentage (OM), cation exchange capacity (CEC meq/100g), electrical conductivity (EC dS/m), bulk density, soil depth to restrictive layer, NRCS hydric soil flag, prime farmland designation, and profile creation/update dates. SSOT for baseline soil physical and chemical characteristics.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`land`.`land_soil_sample` (
    `land_soil_sample_id` BIGINT COMMENT 'Unique system-generated identifier for each individual soil sampling event record. Primary key for the soil_sample data product in the land domain.',
    `field_id` BIGINT COMMENT 'Reference to the agricultural field from which this soil sample was collected. Links to the land domain field master record for GIS boundary and parcel context.',
    `vendor_id` BIGINT COMMENT 'Foreign key linking to procurement.vendor. Business justification: Soil testing laboratories are qualified vendors in the procurement system. Linking soil_sample to the lab vendor enables vendor qualification tracking, invoice matching for lab services, COA verificat',
    `management_zone_id` BIGINT COMMENT 'Reference to the sub-field management zone from which this sample was drawn. Management zones are delineated areas within a field with homogeneous soil characteristics used for Variable Rate Application (VRA) prescription planning.',
    `soil_profile_id` BIGINT COMMENT 'Foreign key linking to land.soil_profile. Business justification: A soil sampling event is conducted within a specific soil mapping unit or management zone that is authoritatively described by a soil_profile record. Linking soil_sample to soil_profile establishes th',
    `base_saturation_pct` DECIMAL(18,2) COMMENT 'Percentage of the soils Cation Exchange Capacity (CEC) occupied by base cations (calcium, magnesium, potassium, sodium). Calculated from individual cation concentrations relative to CEC. Used to assess nutrient balance and guide lime and fertilizer application strategies.',
    `buffer_ph` DECIMAL(18,2) COMMENT 'Buffer pH value measured using a buffered solution (e.g., Shoemaker-McLean-Pratt or Sikora buffer) to determine the lime requirement for acidic soils. Used in conjunction with water pH to calculate the amount of agricultural lime needed to raise soil pH to target levels.',
    `calcium_ppm` DECIMAL(18,2) COMMENT 'Plant-available calcium (Ca) concentration in parts per million (ppm). Calcium is a secondary macronutrient essential for cell wall development and root growth. Also used in calculating percent base saturation and Cation Exchange Capacity (CEC) balance.',
    `cec_meq_100g` DECIMAL(18,2) COMMENT 'Cation Exchange Capacity (CEC) of the soil expressed in milliequivalents per 100 grams of soil (meq/100g). CEC measures the soils ability to hold and supply positively charged nutrient ions (Ca, Mg, K, Na, H). Higher CEC indicates greater nutrient-holding capacity and influences fertilizer efficiency.',
    `coa_reference_number` STRING COMMENT 'Unique reference number of the Certificate of Analysis (COA) issued by the laboratory for this soil sample. The COA is the official document certifying the analytical results and chain of custody.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this soil sample record was first created in the system, in ISO 8601 format (yyyy-MM-ddTHH:mm:ss.SSSXXX). Supports audit trail, data lineage, and Silver layer ingestion tracking.',
    `crop_season_year` STRING COMMENT 'The four-digit crop production year associated with this soil sampling event (e.g., 2024). Used to align soil test results with the corresponding growing season for fertilizer prescription planning and year-over-year soil health trend analysis.',
    `ec_ds_m` DECIMAL(18,2) COMMENT 'Electrical Conductivity (EC) of the soil measured in deciSiemens per meter (dS/m). EC is an indicator of soil salinity and total dissolved salt concentration. High EC values indicate salinity stress risk and influence irrigation management and crop selection decisions.',
    `gps_accuracy_m` DECIMAL(18,2) COMMENT 'Horizontal positional accuracy of the GPS coordinates in meters at time of sample collection. RTK-corrected readings typically achieve sub-0.05m accuracy. Used to assess spatial data quality for precision agriculture applications.',
    `lab_accreditation_number` STRING COMMENT 'Official accreditation or certification number of the laboratory that analyzed the sample, issued by a recognized accreditation body (e.g., A2LA, NELAP). Supports regulatory compliance and audit traceability.',
    `lab_report_date` DATE COMMENT 'Date on which the laboratory issued the official analytical results report for this soil sample. Used to calculate lab turnaround time and determine data currency for fertilizer prescriptions.',
    `lab_submission_date` DATE COMMENT 'Date on which the collected soil sample was submitted to the analytical laboratory for processing. Used to track turnaround time and chain-of-custody compliance.',
    `latitude` DECIMAL(18,2) COMMENT 'GPS latitude coordinate (decimal degrees, WGS84 datum) of the soil sample collection point. Captured via RTK-accurate GPS equipment for precise spatial referencing in GIS systems and VRA prescription mapping.',
    `lime_recommendation_lbs_ac` DECIMAL(18,2) COMMENT 'Laboratory-recommended agricultural lime application rate in pounds per acre, calculated from soil pH and buffer pH results to raise soil pH to the target level for the planned crop. Directly used in fertilizer prescription and VRA lime application planning.',
    `longitude` DECIMAL(18,2) COMMENT 'GPS longitude coordinate (decimal degrees, WGS84 datum) of the soil sample collection point. Captured via RTK-accurate GPS equipment for precise spatial referencing in GIS systems and VRA prescription mapping.',
    `magnesium_ppm` DECIMAL(18,2) COMMENT 'Plant-available magnesium (Mg) concentration in parts per million (ppm). Magnesium is a secondary macronutrient and central component of chlorophyll. Used in CEC base saturation calculations and dolomitic lime application decisions.',
    `nitrate_n_ppm` DECIMAL(18,2) COMMENT 'Plant-available nitrate nitrogen (NO3-N) concentration in parts per million (ppm) as measured in the soil sample. A key component of the Nitrogen-Phosphorus-Potassium (NPK) nutrient profile. Directly informs nitrogen fertilizer application rates and VRA prescriptions.',
    `nitrogen_recommendation_lbs_ac` DECIMAL(18,2) COMMENT 'Laboratory or agronomist-recommended nitrogen (N) fertilizer application rate in pounds per acre based on soil nitrate-N test results, organic matter nitrogen credit, and planned crop yield goal. Core input for NPK fertilizer prescription and VRA planning.',
    `organic_matter_pct` DECIMAL(18,2) COMMENT 'Percentage of organic matter (OM) in the soil sample, measured by loss-on-ignition or Walkley-Black method. Organic matter is a key indicator of soil health, water-holding capacity, and biological activity. Drives nitrogen credit calculations and carbon sequestration assessments.',
    `ph_water` DECIMAL(18,2) COMMENT 'Soil pH measured using the 1:1 soil-to-water suspension method, representing the Potential of Hydrogen (pH) — the primary indicator of soil acidity or alkalinity. Values range from 0-14; optimal crop production typically falls between 6.0-7.0. Drives lime application recommendations.',
    `phosphorus_method` STRING COMMENT 'Laboratory extraction method used to determine plant-available phosphorus concentration. Bray-1 is standard for acidic soils; Mehlich-3 is a universal extractant; Olsen is used for calcareous/alkaline soils. Method must be recorded as results are not directly comparable across methods.. Valid values are `Bray-1|Mehlich-3|Olsen|Colwell`',
    `phosphorus_ppm` DECIMAL(18,2) COMMENT 'Plant-available phosphorus (P) concentration in parts per million (ppm), measured by Bray-1 or Mehlich-3 extraction method. A key component of the Nitrogen-Phosphorus-Potassium (NPK) nutrient profile. Drives phosphate fertilizer recommendations and VRA prescription maps.',
    `phosphorus_recommendation_lbs_ac` DECIMAL(18,2) COMMENT 'Laboratory or agronomist-recommended phosphate (P2O5) fertilizer application rate in pounds per acre based on soil phosphorus test results and planned crop yield goal. Core input for NPK fertilizer prescription and VRA planning.',
    `potassium_ppm` DECIMAL(18,2) COMMENT 'Plant-available potassium (K) concentration in parts per million (ppm), measured by Mehlich-3 or ammonium acetate extraction. A key component of the Nitrogen-Phosphorus-Potassium (NPK) nutrient profile. Drives potash fertilizer recommendations and VRA prescription planning.',
    `potassium_recommendation_lbs_ac` DECIMAL(18,2) COMMENT 'Laboratory or agronomist-recommended potash (K2O) fertilizer application rate in pounds per acre based on soil potassium test results and planned crop yield goal. Core input for NPK fertilizer prescription and VRA planning.',
    `sample_date` DATE COMMENT 'Calendar date on which the soil sample was physically collected from the field. Critical for seasonal trend analysis and determining the agronomic context (pre-plant, post-harvest, etc.).',
    `sample_depth_in` DECIMAL(18,2) COMMENT 'Depth in inches at which the soil sample was collected from the surface. Standard agronomic sampling depths are 0-6 inches (topsoil) or 6-12 inches (subsoil). Critical for interpreting nutrient availability relative to root zone.',
    `sample_method` STRING COMMENT 'Method used to collect the soil sample. Grid sampling uses a systematic spatial grid; zone sampling collects within defined management zones; composite combines multiple cores; benchmark uses fixed reference points for longitudinal tracking.. Valid values are `grid|zone|composite|benchmark|random`',
    `sample_number` STRING COMMENT 'Externally-known, human-readable sample identifier assigned at time of collection, used for lab submission tracking and field cross-referencing. Typically formatted as a lab accession or farm-assigned code (e.g., FARM-2024-F01-Z3).',
    `sample_status` STRING COMMENT 'Current lifecycle status of the soil sample record, tracking progression from field collection through laboratory analysis to agronomic approval for use in fertilizer prescriptions.. Valid values are `collected|submitted|in_analysis|results_received|approved|voided`',
    `sampling_technician` STRING COMMENT 'Name or identifier of the agronomist, certified crop advisor (CCA), or field technician who physically collected the soil sample. Used for chain-of-custody documentation and quality assurance traceability.',
    `soil_texture_class` STRING COMMENT 'USDA soil texture classification based on the relative proportions of sand, silt, and clay particles. Texture class influences water-holding capacity, drainage, tillage requirements, and nutrient management. [ENUM-REF-CANDIDATE: sand|loamy_sand|sandy_loam|loam|silt_loam|silt|sandy_clay_loam|clay_loam|silty_clay_loam|sandy_clay|silty_clay|clay — promote to reference product]',
    `sulfur_ppm` DECIMAL(18,2) COMMENT 'Plant-available sulfur (S) concentration in parts per million (ppm). Sulfur is a secondary macronutrient critical for protein synthesis and enzyme function. Deficiencies are increasingly common in high-yield cropping systems and drive sulfur fertilizer recommendations.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent modification to this soil sample record, in ISO 8601 format (yyyy-MM-ddTHH:mm:ss.SSSXXX). Used for change detection, incremental data pipeline processing, and audit compliance.',
    `zinc_ppm` DECIMAL(18,2) COMMENT 'Plant-available zinc (Zn) micronutrient concentration in parts per million (ppm), measured by Mehlich-3 or DTPA extraction. Zinc deficiency is common in high-pH soils and drives micronutrient fertilizer recommendations for corn and other sensitive crops.',
    CONSTRAINT pk_land_soil_sample PRIMARY KEY(`land_soil_sample_id`)
) COMMENT 'Individual soil sampling event record capturing laboratory-analyzed nutrient and chemical results for a specific field zone or GPS-referenced sample point. Stores sample date, lab submission date, lab report date, lab name, sample depth (inches), GPS coordinates, management zone ID, pH (1:1 water), buffer pH, organic matter (%), nitrate-N (ppm), phosphorus (P Bray/Mehlich-3 ppm), potassium (K ppm), calcium (Ca ppm), magnesium (Mg ppm), sulfur (S ppm), zinc (Zn ppm), CEC (meq/100g), EC (dS/m), percent base saturation, and COA reference number. Core to NPK fertilizer prescription and VRA planning.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`land`.`management_zone` (
    `management_zone_id` BIGINT COMMENT 'Unique surrogate identifier for the management zone record in the Databricks Silver Layer lakehouse. Primary key for this entity.',
    `field_id` BIGINT COMMENT 'Reference to the parent agricultural field within which this management zone is spatially defined. Links to the land domain field entity.',
    `growing_season_id` BIGINT COMMENT 'Reference to the growing season for which this management zone configuration is active. Management zone boundaries and soil attribute values may be updated between growing seasons as new soil sampling and yield data become available.',
    `soil_profile_id` BIGINT COMMENT 'Foreign key linking to land.soil_profile. Business justification: A management zone is delineated based on soil characteristics (EC, pH, OM, CEC, texture) that are authoritatively captured in the soil_profile entity. Linking management_zone to soil_profile formalize',
    `agronomist_notes` STRING COMMENT 'Free-text field for agronomist or crop consultant observations about the management zone, including special management considerations, historical problem areas, or recommendations for upcoming season. Captured in Granular Farm Management or Trimble Ag Software during field scouting.',
    `area_acres` DECIMAL(18,2) COMMENT 'Calculated spatial area of the management zone expressed in acres, derived from the GIS polygon geometry. Used for VRA prescription rate calculations, input cost allocation, and yield-per-acre (YPM) reporting. Precision to four decimal places supports sub-acre zone granularity.',
    `area_hectares` DECIMAL(18,2) COMMENT 'Calculated spatial area of the management zone expressed in hectares for international reporting and metric-system compliance. Supports GLOBALG.A.P. and ISO 14001 environmental reporting requirements.',
    `cec_meq_100g` DECIMAL(18,2) COMMENT 'Mean cation exchange capacity (CEC) of the management zone soil expressed in milliequivalents per 100 grams (meq/100g). Measures the soils ability to hold and supply positively charged nutrient ions (Ca, Mg, K, Na). Higher CEC indicates greater nutrient-holding capacity. Used for fertilizer rate calibration and soil amendment planning.',
    `centroid_latitude` DECIMAL(18,2) COMMENT 'Latitude coordinate of the management zone polygon centroid in decimal degrees (WGS84). Used for GPS (Global Positioning System) navigation, weather station proximity matching, and spatial analytics in Esri ArcGIS.',
    `centroid_longitude` DECIMAL(18,2) COMMENT 'Longitude coordinate of the management zone polygon centroid in decimal degrees (WGS84). Used for GPS navigation, weather data correlation, and spatial analytics in Esri ArcGIS.',
    `conservation_practice_code` STRING COMMENT 'USDA NRCS conservation practice standard code applied to this management zone (e.g., 590 - Nutrient Management, 329 - Residue and Tillage Management, 340 - Cover Crop, 412 - Grassed Waterway). Supports USDA EQIP (Environmental Quality Incentives Program) compliance reporting and ISO 14001 environmental management documentation.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this management zone record was first created in the lakehouse Silver Layer, in ISO 8601 format (yyyy-MM-ddTHH:mm:ss.SSSXXX). Supports audit trail and data lineage requirements.',
    `delineation_method` STRING COMMENT 'Method used to spatially delineate the management zone boundary. EC (Electrical Conductivity) scanning uses Veris or EM38 sensors; yield history uses multi-year combine yield monitor data from Climate FieldView or John Deere Operations Center; satellite NDVI uses remote sensing imagery; manual uses operator-drawn boundaries in Esri ArcGIS or Trimble Ag; soil sampling uses interpolated soil test point data; topographic analysis uses digital elevation model (DEM) data.. Valid values are `ec_scanning|yield_history|satellite_ndvi|manual|soil_sampling|topographic_analysis`',
    `delineation_year` STRING COMMENT 'Calendar year in which the management zone boundary was originally delineated or most recently revised. Used to assess zone data currency and schedule periodic re-delineation based on updated EC scanning, yield history, or satellite imagery data.',
    `drainage_class` STRING COMMENT 'USDA NRCS soil drainage class for the management zone, indicating the natural rate of water removal from the soil profile. Affects crop selection, planting date decisions, and tile drainage infrastructure planning. Poorly drained zones may qualify for wetland conservation programs.. Valid values are `excessively_drained|well_drained|moderately_well_drained|somewhat_poorly_drained|poorly_drained`',
    `ec_deep_ds_m` DECIMAL(18,2) COMMENT 'Apparent soil electrical conductivity (EC) reading at deep depth (typically 0-90 cm) expressed in deciSiemens per meter (dS/m). Measured via Veris 3100 or EM38 sensor. Reflects subsoil characteristics including clay pan depth and water-holding capacity. Complements shallow EC for comprehensive zone delineation.',
    `ec_scan_date` DATE COMMENT 'Date on which the soil electrical conductivity (EC) scanning survey was conducted for this management zone. Used to assess data currency and schedule re-scanning intervals (typically every 3-5 years per BMP guidelines).',
    `ec_shallow_ds_m` DECIMAL(18,2) COMMENT 'Apparent soil electrical conductivity (EC) reading at shallow depth (typically 0-30 cm) expressed in deciSiemens per meter (dS/m). Measured via Veris 3100 or EM38 sensor during EC scanning. Correlates with soil texture, clay content, and salinity. Used as primary input for EC-based zone delineation and VRA (Variable Rate Application) prescription generation.',
    `external_zone_code` STRING COMMENT 'Native identifier of this management zone in the originating source system (e.g., Trimble Ag zone GUID, John Deere Operations Center zone ID, Esri ArcGIS feature OID). Enables bidirectional synchronization and traceability between the lakehouse Silver Layer and operational precision agriculture platforms.',
    `gis_polygon_wkt` STRING COMMENT 'Spatial boundary of the management zone stored as Well-Known Text (WKT) polygon geometry in WGS84 coordinate reference system (EPSG:4326). Sourced from Esri ArcGIS or John Deere Operations Center RTK-accurate field mapping. Enables spatial joins with soil sampling points, yield data, and satellite imagery layers.',
    `last_soil_sample_date` DATE COMMENT 'Date of the most recent composite soil sampling event conducted within this management zone. Used to assess soil data currency and trigger re-sampling workflows. GLOBALG.A.P. and USDA NRCS BMP guidelines recommend soil sampling every 2-4 years.',
    `ndvi_image_date` DATE COMMENT 'Date on which the satellite or aerial imagery used to calculate the current NDVI value was captured. Critical for assessing data currency and seasonal relevance of the vegetation index reading.',
    `ndvi_value` DECIMAL(18,2) COMMENT 'Most recent NDVI (Normalized Difference Vegetation Index) value for the management zone, ranging from -1.0 to 1.0. Derived from satellite or aerial multispectral imagery. Values above 0.5 indicate dense, healthy vegetation; values below 0.2 indicate sparse or stressed vegetation. Used for in-season crop monitoring and zone reclassification.',
    `nitrogen_lbs_acre` DECIMAL(18,2) COMMENT 'Mean available nitrogen (N) level in the management zone soil expressed in pounds per acre (lbs/acre), derived from composite soil sampling. Component of NPK (Nitrogen Phosphorus Potassium) nutrient profile. Used to calculate nitrogen fertilizer application rates in VRA prescriptions and comply with nutrient management plan requirements.',
    `organic_matter_pct` DECIMAL(18,2) COMMENT 'Mean soil organic matter (OM) content expressed as a percentage of dry soil weight for the management zone. Measured via loss-on-ignition or Walkley-Black method from composite soil samples. Higher OM improves water retention, nutrient cycling, and soil structure. Key indicator for carbon sequestration reporting under ISCC and sustainability programs.',
    `phosphorus_lbs_acre` DECIMAL(18,2) COMMENT 'Mean available phosphorus (P) level in the management zone soil expressed in pounds per acre (lbs/acre), derived from composite soil sampling. Component of NPK nutrient profile. Used to calculate phosphorus fertilizer application rates in VRA prescriptions and support EPA water quality compliance for phosphorus runoff management.',
    `potassium_lbs_acre` DECIMAL(18,2) COMMENT 'Mean available potassium (K) level in the management zone soil expressed in pounds per acre (lbs/acre), derived from composite soil sampling. Component of NPK nutrient profile. Used to calculate potassium fertilizer application rates in VRA prescriptions.',
    `productivity_class` STRING COMMENT 'Agronomic productivity classification of the management zone based on historical yield performance and soil capability. High productivity zones receive premium input rates; low productivity zones may receive reduced inputs or conservation treatment under BMP (Best Management Practices) guidelines.. Valid values are `high|medium|low`',
    `slope_pct` DECIMAL(18,2) COMMENT 'Mean slope gradient of the management zone expressed as a percentage (rise over run × 100), derived from digital elevation model (DEM) analysis in Esri ArcGIS. Used for erosion risk assessment, drainage planning, and equipment operation safety. Slopes above 8% may require conservation practices under USDA NRCS BMP guidelines.',
    `soil_ph_mean` DECIMAL(18,2) COMMENT 'Mean soil pH (Potential of Hydrogen) value for the management zone, representing average soil acidity or alkalinity on a 0-14 scale. Calculated from composite soil samples within the zone. Critical for nutrient availability assessment and lime application rate determination in VRA prescriptions. Optimal range for most crops is 6.0-7.0.',
    `soil_texture_class` STRING COMMENT 'USDA soil texture classification for the dominant soil type within the management zone, based on relative proportions of sand, silt, and clay particles. Determines water infiltration rate, water-holding capacity, and tillage characteristics. Used for irrigation scheduling and equipment operation planning. [ENUM-REF-CANDIDATE: sand|loamy_sand|sandy_loam|loam|silt_loam|silt|sandy_clay_loam|clay_loam|silty_clay_loam|sandy_clay|silty_clay|clay — promote to reference product]',
    `source_system` STRING COMMENT 'Operational system of record from which this management zone record was originated or last updated. Supports data lineage tracking and conflict resolution when zone data is synchronized across multiple precision agriculture platforms.. Valid values are `trimble_ag|john_deere_ops|climate_fieldview|granular|arcgis|manual`',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this management zone record was most recently modified in the lakehouse Silver Layer, in ISO 8601 format (yyyy-MM-ddTHH:mm:ss.SSSXXX). Used to detect stale zone configurations and trigger re-synchronization with source precision agriculture systems.',
    `vra_eligible` BOOLEAN COMMENT 'Indicates whether this management zone is eligible for variable rate application (VRA) prescription generation in Trimble Ag Software or John Deere Operations Center. Zones must meet minimum area thresholds and have current soil data to qualify for VRA. True = eligible for VRA prescriptions; False = not eligible.',
    `zone_code` STRING COMMENT 'Externally-known alphanumeric code uniquely identifying the management zone within the farm management information system (FMIS). Used as the business key in Trimble Ag Software and John Deere Operations Center for variable rate application (VRA) prescription generation.. Valid values are `^[A-Z0-9_-]{2,20}$`',
    `zone_name` STRING COMMENT 'Human-readable descriptive name assigned to the management zone (e.g., North Field High Productivity Zone, EC Zone 3 - Sandy Loam). Used in FMIS reporting and VRA prescription labeling.',
    `zone_status` STRING COMMENT 'Current lifecycle status of the management zone. Active zones are used in current-season VRA prescriptions; inactive zones are temporarily suspended; archived zones are retained for historical analysis; draft zones are pending agronomist review and approval.. Valid values are `active|inactive|archived|draft`',
    `zone_type` STRING COMMENT 'Classification of the zone based on the primary agronomic criterion used to define it. Soil type zones are delineated by soil series; EC (Electrical Conductivity) zones by apparent soil EC readings; yield zones by multi-year yield history; topographic zones by elevation and slope; NDVI (Normalized Difference Vegetation Index) zones by satellite-derived vegetation index; management zones by operator-defined boundaries.. Valid values are `soil_type|ec_zone|yield_zone|topographic_zone|ndvi_zone|management_zone`',
    `zone_version` STRING COMMENT 'Sequential version number of the management zone boundary definition, incremented each time the zone polygon or classification attributes are revised. Supports audit trail and historical comparison of zone configurations across growing seasons.',
    CONSTRAINT pk_management_zone PRIMARY KEY(`management_zone_id`)
) COMMENT 'Spatially defined sub-field management zone used for variable rate application (VRA) prescriptions, precision nutrient management, and yield zone analysis. Captures zone name, zone code, zone type (soil type, EC zone, yield zone, topographic zone), delineation method (EC scanning, yield history, satellite NDVI, manual), zone area (acres), GIS polygon geometry, NDVI index value, EC shallow/deep readings, zone classification (high/medium/low productivity), and active flag. Integrates with Trimble Ag and John Deere Operations Center for VRA prescription generation.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`land`.`field_boundary` (
    `field_boundary_id` BIGINT COMMENT 'Unique surrogate identifier for each versioned field boundary record in the land domain. Primary key for the field_boundary data product. Role: MASTER_RESOURCE.',
    `farm_unit_id` BIGINT COMMENT 'Reference to the farm or operation that owns or manages this field boundary. Supports multi-farm enterprise hierarchies in Granular Farm Management and SAP S/4HANA land management.',
    `field_id` BIGINT COMMENT 'Reference to the parent agricultural field entity that this boundary version describes. Multiple boundary versions may exist for the same field over time as boundaries are split, merged, or re-surveyed.',
    `tertiary_trimble_field_id` BIGINT COMMENT 'Field identifier assigned by Trimble Ag Software for variable rate prescription (VRA) and crop scouting integration. Enables linkage of boundary geometry with Trimble-generated field plans and prescription maps.',
    `accuracy_class` STRING COMMENT 'Positional accuracy classification of the boundary geometry. RTK indicates centimeter-level accuracy from Real-Time Kinematic GPS survey; sub_meter indicates accuracy better than 1 meter; meter indicates accuracy within 1-5 meters; multi_meter indicates accuracy greater than 5 meters (e.g., from manual digitization or low-resolution imagery).. Valid values are `RTK|sub_meter|meter|multi_meter`',
    `accuracy_meters` DECIMAL(18,2) COMMENT 'Quantitative positional accuracy of the boundary geometry expressed in meters (root mean square error or circular error probable). Complements accuracy_class with a precise numeric value for spatial quality assessment and compliance reporting.',
    `arcgis_feature_class_ref` STRING COMMENT 'Reference identifier for the corresponding feature class and object ID within the Esri ArcGIS geodatabase. Enables direct linkage between this data product and the authoritative GIS source layer for spatial queries and map rendering.',
    `area_acres` DECIMAL(18,2) COMMENT 'Total calculated area of the field boundary in acres, derived from the boundary geometry. Used for FSA compliance reporting, crop insurance acreage certification, input application rate calculations, and yield per acre (YPM) computations. This is the authoritative GIS-calculated area, not a surveyed or estimated value.',
    `area_hectares` DECIMAL(18,2) COMMENT 'Total calculated area of the field boundary in hectares, derived from the boundary geometry. Used for international reporting, metric-system compliance, and integration with global agricultural standards (GLOBALG.A.P., ISO 14001 environmental reporting).',
    `boundary_code` STRING COMMENT 'Externally-known alphanumeric code uniquely identifying this field boundary within the farm management information system (FMIS). Used for cross-system referencing between ArcGIS, John Deere Operations Center, and SAP S/4HANA.. Valid values are `^[A-Z0-9_-]{2,30}$`',
    `boundary_name` STRING COMMENT 'Human-readable name assigned to this field boundary, typically matching the field name used operationally (e.g., North 40, River Bottom Field). Serves as the primary identity label for business users.',
    `boundary_source` STRING COMMENT 'Method or technology used to capture or derive this field boundary. RTK_GPS_survey indicates Real-Time Kinematic (RTK) GPS ground survey; drone_imagery indicates boundary derived from UAV aerial imagery; ArcGIS_digitized indicates manual digitization in Esri ArcGIS; satellite_imagery indicates derivation from satellite imagery; manual_entry indicates operator-entered coordinates.. Valid values are `RTK_GPS_survey|drone_imagery|ArcGIS_digitized|satellite_imagery|manual_entry`',
    `boundary_status` STRING COMMENT 'Current lifecycle status of this boundary version. active indicates the current operative boundary; superseded indicates a prior version replaced by a newer one; draft indicates a boundary under review before activation; retired indicates a boundary no longer in use; pending_review indicates awaiting FSA or agronomist validation.. Valid values are `active|superseded|draft|retired|pending_review`',
    `boundary_version` STRING COMMENT 'Sequential version number of this boundary record for the parent field. Increments each time the boundary is re-surveyed, split, merged, or corrected. Version 1 is the initial boundary; higher numbers represent subsequent revisions.',
    `centroid_latitude` DECIMAL(18,2) COMMENT 'Latitude coordinate of the field boundary centroid in decimal degrees (WGS84 / EPSG:4326). Used for weather station assignment, solar radiation modeling, and quick spatial lookups without full geometry processing.',
    `centroid_longitude` DECIMAL(18,2) COMMENT 'Longitude coordinate of the field boundary centroid in decimal degrees (WGS84 / EPSG:4326). Used alongside centroid_latitude for weather station assignment, logistics routing, and spatial indexing.',
    `clu_identifier` STRING COMMENT 'USDA Common Land Unit (CLU) unique identifier for this field boundary. The CLU is the smallest unit of land that has a permanent, contiguous boundary and is used as the basis for USDA farm program administration and acreage reporting.',
    `conservation_program` STRING COMMENT 'Name or code of the USDA conservation program in which this field boundary is enrolled (e.g., CRP for Conservation Reserve Program, EQIP for Environmental Quality Incentives Program, WRP for Wetland Reserve Program). Null if not enrolled in any conservation program.',
    `country_code` STRING COMMENT 'Three-letter ISO 3166-1 alpha-3 country code identifying the country in which this field boundary is located (e.g., USA). Supports international operations and GLOBALG.A.P. country-of-origin labeling (COOL) compliance.. Valid values are `^[A-Z]{3}$`',
    `county_fips_code` STRING COMMENT 'Five-digit Federal Information Processing Standards (FIPS) code identifying the US county in which this field boundary is located. Required for USDA FSA county office assignment, crop insurance rating, and regulatory jurisdiction determination.. Valid values are `^[0-9]{5}$`',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this field boundary record was first created in the system, in ISO 8601 format (yyyy-MM-ddTHH:mm:ss.SSSXXX). Provides the audit trail creation anchor for data lineage and compliance reporting.',
    `crs_epsg_code` STRING COMMENT 'EPSG (European Petroleum Survey Group) numeric code identifying the coordinate reference system (CRS) in which the boundary geometry coordinates are expressed (e.g., 4326 for WGS84, 32614 for UTM Zone 14N). Critical for accurate spatial calculations and cross-system interoperability.',
    `effective_end_date` DATE COMMENT 'Date on which this boundary version ceases to be operative, typically when superseded by a new version due to field split, merge, or re-survey. Null indicates the boundary is currently active with no defined end date.',
    `effective_start_date` DATE COMMENT 'Date from which this boundary version is considered operative and legally binding for FSA compliance, crop insurance, and land management purposes. Marks the beginning of the temporal validity window for this boundary record.',
    `elevation_avg_meters` DECIMAL(18,2) COMMENT 'Average elevation of the field above mean sea level in meters, derived from digital elevation model (DEM) data. Used for microclimate analysis, frost risk assessment, and precision agriculture zone delineation.',
    `fsa_field_number` STRING COMMENT 'USDA Farm Service Agency (FSA) field number within the assigned tract. Together with fsa_tract_number, uniquely identifies this field in the USDA Common Land Unit (CLU) registry for federal program compliance and acreage certification.',
    `fsa_tract_number` STRING COMMENT 'USDA Farm Service Agency (FSA) tract number assigned to this field for federal program compliance, acreage reporting, and crop insurance purposes. Required for ARC/PLC program enrollment and FSA farm records.',
    `geometry_type` STRING COMMENT 'GIS geometry type of the boundary shape as defined by ISO 19125 Simple Features. Polygon for contiguous single-parcel fields; MultiPolygon for non-contiguous fields composed of multiple disconnected parcels (e.g., fields separated by roads or waterways).. Valid values are `Polygon|MultiPolygon`',
    `geometry_wkt` STRING COMMENT 'Full boundary geometry encoded in Well-Known Text (WKT) format as per OGC standards. Stores the polygon or multipolygon coordinate ring defining the precise field boundary. Used by Esri ArcGIS and John Deere Operations Center for spatial analysis and field mapping.',
    `irrigation_type` STRING COMMENT 'Primary irrigation method applied to this field boundary. Informs water resource management planning, evapotranspiration (ET) calculations, and irrigation event scheduling in the crop management domain.. Valid values are `drip|sprinkler|flood|center_pivot|subsurface|rainfed`',
    `is_gmo_restricted` BOOLEAN COMMENT 'Indicates whether this field boundary has a contractual or certification-based restriction prohibiting the planting of genetically modified organism (GMO) crops. True if GMO planting is prohibited; False if GMO crops are permitted.',
    `is_organic_certified` BOOLEAN COMMENT 'Indicates whether this field boundary is enrolled in and certified under the USDA National Organic Program (NOP). True if the field carries active organic certification; False otherwise. Drives organic input restrictions and segregation requirements.',
    `land_use_type` STRING COMMENT 'Primary land use classification for this field boundary. Determines applicable regulatory requirements, conservation program eligibility, and crop planning constraints. [ENUM-REF-CANDIDATE: cropland|pasture|orchard|vineyard|fallow|wetland|woodland|conservation|other — promote to reference product]',
    `perimeter_meters` DECIMAL(18,2) COMMENT 'Total calculated perimeter length of the field boundary in meters, derived from the boundary geometry. Used for fencing cost estimation, irrigation system design, and field edge management planning.',
    `slope_percent` DECIMAL(18,2) COMMENT 'Average slope of the field expressed as a percentage (rise over run × 100). Used for erosion risk assessment, drainage planning, variable rate application (VRA) prescriptions, and conservation practice eligibility under USDA NRCS programs.',
    `state_code` STRING COMMENT 'Two-letter US state abbreviation (ISO 3166-2:US) identifying the state in which this field boundary is located. Used for state-level regulatory compliance, FSA state office routing, and geographic reporting.. Valid values are `^[A-Z]{2}$`',
    `survey_date` DATE COMMENT 'Date on which the field boundary was physically surveyed or digitized to produce this version. Used to assess boundary currency, trigger re-survey workflows, and support FSA acreage certification timelines.',
    `surveyed_by` STRING COMMENT 'Name or identifier of the person, organization, or system that performed or certified the boundary survey (e.g., licensed surveyor name, drone service provider, or system name such as John Deere Operations Center Auto-Boundary). Supports audit trail and data quality accountability.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent modification to this field boundary record, in ISO 8601 format (yyyy-MM-ddTHH:mm:ss.SSSXXX). Used for change detection, incremental data pipeline processing, and audit trail maintenance.',
    CONSTRAINT pk_field_boundary PRIMARY KEY(`field_boundary_id`)
) COMMENT 'Versioned GIS boundary geometry record for each field, supporting boundary change history as fields are split, merged, or re-surveyed. Stores boundary version number, effective start date, effective end date, geometry type (polygon/multipolygon), coordinate reference system (CRS/EPSG code), boundary source (RTK GPS survey, drone imagery, ArcGIS digitized), total calculated area (acres), perimeter (feet/meters), boundary accuracy class (RTK/sub-meter/meter), ArcGIS feature class reference, and John Deere Operations Center field ID. Enables temporal boundary tracking for FSA compliance and crop insurance.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`land`.`use_plan` (
    `use_plan_id` BIGINT COMMENT 'Unique system-generated identifier for the land use plan record. Primary key for the land_use_plan data product in the land domain.',
    `commodity_id` BIGINT COMMENT 'Foreign key linking to product.commodity. Business justification: FSA Acreage Reporting and Crop Insurance enrollment require land use plans to reference the commodity master for standardized commodity codes, grade standards, and MRL applicability. planned_commodity',
    `farm_unit_id` BIGINT COMMENT 'Reference to the farm or operation unit to which the planned field belongs. Supports farm-level aggregation of land use planning across multiple fields.',
    `field_id` BIGINT COMMENT 'Reference to the agricultural field parcel to which this land use plan applies. Links to the field master record containing GIS boundary, acreage, and soil profile data.',
    `growing_season_id` BIGINT COMMENT 'Foreign key linking to crop.growing_season. Business justification: Land use plans are annual FSA/USDA documents aligned to specific crop years and growing seasons. Linking land_use_plan to growing_season enables FSA compliance reporting, crop insurance unit alignment',
    `management_zone_id` BIGINT COMMENT 'Foreign key linking to land.management_zone. Business justification: Land use planning in precision agriculture is increasingly conducted at the sub-field management zone level — different zones within a field may have different planned commodities, tillage systems, ta',
    `obligation_id` BIGINT COMMENT 'Foreign key linking to compliance.compliance_obligation. Business justification: Land use plans under conservation programs (CRP, EQIP) create compliance obligations (practice installation deadlines, cover crop requirements, reporting dates). Linking land_use_plan to its governing',
    `organic_certification_id` BIGINT COMMENT 'Foreign key linking to product.organic_certification. Business justification: NOP annual organic plan approval requires each land use plan year to reference the specific organic certification in force for that crop year, enabling certificate validity checks, allowed materials l',
    `permit_id` BIGINT COMMENT 'Foreign key linking to compliance.permit. Business justification: Land use plans for CRP enrollment, organic production, or restricted-use areas may be governed by specific permits. Linking land_use_plan to the governing permit enables compliance tracking for planne',
    `rotation_plan_id` BIGINT COMMENT 'Reference to the multi-year crop rotation plan that governs the sequence of crops for this field. Links to the crop.rotation_plan product for full rotation cycle details.',
    `seed_variety_id` BIGINT COMMENT 'Foreign key linking to product.seed_variety. Business justification: Agronomic Season Planning process: land use plans specify the seed variety for each field-year to support GMO compliance checks (field gmo_restricted vs variety gmo_status), organic eligibility alignm',
    `approved_by` STRING COMMENT 'Name or identifier of the farm manager, agronomist, or authorized personnel who approved the land use plan. Supports audit trail and authorization workflow documentation for FSA program compliance.',
    `approved_date` DATE COMMENT 'The date on which the land use plan was formally approved by the authorized farm manager or agronomist. Required for FSA program compliance documentation and GLOBALG.A.P. audit trail.',
    `conservation_practice` STRING COMMENT 'Planned USDA NRCS conservation practice code or description for the field (e.g., 590 - Nutrient Management, 329 - Residue and Tillage Management, 340 - Cover and Green Manure Crop). Supports EQIP and CSP program compliance and BMP documentation.',
    `cover_crop_species` STRING COMMENT 'Planned cover crop species or mix to be planted on the field (e.g., cereal rye, crimson clover, radish, oats). Applicable when land_use_type is cover_crop or when a cover crop is planned following the primary commodity. Supports soil health and NRCS conservation practice documentation.',
    `created_timestamp` TIMESTAMP COMMENT 'The date and time when the land use plan record was first created in the system. Supports audit trail, data lineage, and compliance documentation requirements under FSMA and GLOBALG.A.P.',
    `crop_insurance_policy_number` STRING COMMENT 'USDA RMA crop insurance policy number associated with this field for the crop year. Links the land use plan to the crop insurance coverage record for acreage reporting, indemnity claims, and APH documentation.',
    `crop_insurance_type` STRING COMMENT 'USDA RMA crop insurance plan type elected for this field. APH: Actual Production History; RP: Revenue Protection; RPHPE: Revenue Protection with Harvest Price Exclusion; YP: Yield Protection; AIP: Area Insurance Plan; WFRP: Whole-Farm Revenue Protection.. Valid values are `aph|rp|rphpe|yp|aip|wfrp`',
    `crop_year` STRING COMMENT 'The agricultural crop year (e.g., 2024) for which this land use plan is defined. Aligns with USDA FSA program year and crop insurance reporting periods. A single field may have one active plan per crop year.',
    `crp_contract_number` STRING COMMENT 'USDA FSA-assigned CRP contract number for the field enrollment. Required for FSA program compliance reporting and annual rental payment reconciliation. Null when crp_enrolled is False.',
    `crp_enrolled` BOOLEAN COMMENT 'Indicates whether this field is enrolled in the USDA Conservation Reserve Program (CRP) for the plan period (True = CRP enrolled; False = not enrolled). CRP enrollment restricts commodity production and triggers conservation practice requirements and annual rental payments.',
    `crp_practice_code` STRING COMMENT 'USDA FSA conservation practice code assigned to the CRP contract (e.g., CP1 - Introduced Grasses, CP21 - Filter Strips, CP38 - SAFE for Upland Birds). Defines the conservation cover type and management requirements for the enrolled acres.',
    `data_source_system` STRING COMMENT 'Identifies the originating operational system of record from which this land use plan record was sourced or integrated. Supports data lineage, reconciliation, and silver layer provenance tracking in the Databricks lakehouse. [ENUM-REF-CANDIDATE: granular|trimble|climate_fieldview|john_deere_ops|arcgis|sap_s4hana|manual — 7 candidates stripped; promote to reference product]',
    `fsa_clu_number` STRING COMMENT 'USDA FSA Common Land Unit (CLU) identifier for the specific field boundary. The CLU is the smallest unit of land with a permanent, contiguous boundary used for FSA program administration and acreage reporting.',
    `fsa_farm_number` STRING COMMENT 'USDA Farm Service Agency (FSA) assigned farm number for the operation. Required for FSA program participation, commodity program payments, and acreage reporting. Links the land use plan to the official FSA farm record.. Valid values are `^[0-9]{1,7}$`',
    `fsa_tract_number` STRING COMMENT 'USDA FSA tract number identifying the specific land tract within the FSA farm record. A farm may contain multiple tracts; each tract contains one or more CLU fields. Required for FSA acreage reporting and program compliance.. Valid values are `^[0-9]{1,7}$`',
    `gmo_planned` BOOLEAN COMMENT 'Indicates whether genetically modified organism (GMO) seed varieties are planned for use on this field in the crop year (True = GMO seed planned; False = non-GMO). Relevant for identity preservation programs, export compliance, and COOL (Country of Origin Labeling) requirements.',
    `irrigation_method` STRING COMMENT 'Planned irrigation delivery method for the field when irrigation is indicated. Center Pivot: overhead rotating system; Drip: surface drip tape; Flood: furrow/flood irrigation; Subsurface Drip: buried drip tape; Sprinkler: fixed or traveling sprinkler. Null when irrigation_planned is False.. Valid values are `center_pivot|drip|flood|subsurface_drip|sprinkler`',
    `irrigation_planned` BOOLEAN COMMENT 'Indicates whether irrigation is planned for this field in the crop year (True = irrigation planned; False = dryland/rainfed production). Drives water resource management planning, evapotranspiration (ET) budgeting, and irrigation infrastructure scheduling.',
    `land_use_type` STRING COMMENT 'Primary intended use classification for the field in the planned crop year. Row Crop: commodity grain/oilseed production; Pasture: livestock grazing; Hay: forage harvest; Fallow: intentional rest; Cover Crop: soil health/erosion control; CRP: Conservation Reserve Program enrollment; Wetland: wetland conservation designation. [ENUM-REF-CANDIDATE: row_crop|pasture|hay|fallow|cover_crop|crp|wetland — promote to reference product]',
    `last_updated_timestamp` TIMESTAMP COMMENT 'The date and time when the land use plan record was most recently modified. Supports change tracking, audit trail, and data lineage requirements for FSA program compliance and GLOBALG.A.P. certification.',
    `organic_certified` BOOLEAN COMMENT 'Indicates whether this field is certified organic under the USDA National Organic Program (NOP) for the planned crop year (True = certified organic; False = conventional). Drives input restrictions, record-keeping requirements, and premium pricing eligibility.',
    `plan_notes` STRING COMMENT 'Free-text field for agronomist or farm manager notes regarding special considerations, deviations from standard rotation, environmental constraints, or other planning context relevant to this fields land use plan.',
    `plan_number` STRING COMMENT 'Externally-known business identifier for the land use plan, formatted as LUP-{YEAR}-{SEQUENCE}. Used for cross-referencing with FSA farm program submissions, crop insurance acreage reports, and FMIS records.. Valid values are `^LUP-[0-9]{4}-[0-9]{6}$`',
    `plan_status` STRING COMMENT 'Current lifecycle status of the land use plan. Draft: initial creation; Approved: reviewed and authorized by farm manager; Active: plan is being executed in the current crop year; Completed: all planned activities concluded; Cancelled: plan voided before execution.. Valid values are `draft|approved|active|completed|cancelled`',
    `plan_year_end_date` DATE COMMENT 'The calendar date on which the land use plan period ends, typically the end of the crop year or harvest completion. Used for plan lifecycle management and multi-year planning horizon tracking.',
    `plan_year_start_date` DATE COMMENT 'The calendar date on which the land use plan period begins, typically the start of the crop year (e.g., January 1 or the beginning of the growing season). Used for plan effective period management and FSA program year alignment.',
    `planned_acres` DECIMAL(18,2) COMMENT 'Total planned production or conservation acres for this field in the crop year, measured in acres. Used for FSA acreage reporting, crop insurance coverage calculations, and input planning (seed, fertilizer, chemical). Aligns with FSA CLU (Common Land Unit) acreage.',
    `rotation_sequence` STRING COMMENT 'Numeric position of this crop in the planned multi-year rotation cycle for the field (e.g., 1 = first year of rotation, 2 = second year). Supports crop rotation planning for soil health, pest management (IPM), and nutrient cycling optimization.',
    `source_record_code` STRING COMMENT 'The native record identifier from the originating source system (e.g., Granular plan ID, Trimble field plan ID). Enables traceability back to the system of record for reconciliation and audit purposes in the silver layer.',
    `target_yield` DECIMAL(18,2) COMMENT 'Planned or expected crop yield for the field in the crop year, expressed in the commoditys standard unit of measure (bushels per acre for grain, tons per acre for forage). Used for input planning, crop insurance APH (Actual Production History) benchmarking, and financial planning.',
    `tillage_system` STRING COMMENT 'Planned tillage practice for the field in the crop year. No-Till: no soil disturbance; Strip-Till: narrow band tillage; Reduced-Till: minimal tillage passes; Conventional-Till: full inversion tillage. Supports BMP compliance, carbon sequestration tracking, and USDA NRCS conservation program eligibility.. Valid values are `no_till|strip_till|reduced_till|conventional_till`',
    `yield_unit` STRING COMMENT 'Unit of measure for the target_yield field. BU/acre (Bushel per Acre) for grain crops; CWT/acre (Hundredweight per Acre) for some specialty crops; Ton/acre for forage; LB/acre for some specialty crops; MT/hectare for metric reporting.. Valid values are `bu_per_acre|cwt_per_acre|ton_per_acre|lb_per_acre|mt_per_hectare`',
    CONSTRAINT pk_use_plan PRIMARY KEY(`use_plan_id`)
) COMMENT 'Annual or multi-year land use planning record assigning intended crop rotation, land use type, and conservation designations to each field for a given crop year. Captures crop year, planned crop (commodity), planned rotation sequence, land use type (row crop, pasture, hay, fallow, cover crop, CRP, wetland), conservation reserve program (CRP) enrollment flag, CRP contract number, planned tillage system (no-till, strip-till, conventional), irrigation plan flag, and plan status (draft/approved/active/completed). Supports FSA farm program compliance and crop insurance acreage reporting.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`land`.`conservation_practice` (
    `conservation_practice_id` BIGINT COMMENT 'Unique system-generated identifier for each conservation practice record implemented on a field or parcel.',
    `field_id` BIGINT COMMENT 'Reference to the field or parcel on which this conservation practice is implemented, as mapped in the GIS/ArcGIS field boundary layer.',
    `management_zone_id` BIGINT COMMENT 'Foreign key linking to land.management_zone. Business justification: Conservation and BMP practices (cover crops, buffer strips, drainage tile, nutrient management) are increasingly implemented at the sub-field management zone level to support variable-rate and precisi',
    `obligation_id` BIGINT COMMENT 'Foreign key linking to compliance.compliance_obligation. Business justification: Conservation practices installed under EQIP, CSP, or CRP create compliance obligations (maintenance requirements, practice lifespan requirements, annual reporting). Linking conservation_practice to it',
    `parcel_id` BIGINT COMMENT 'Reference to the land parcel record associated with this conservation practice, supporting ownership and lease tracking.',
    `permit_id` BIGINT COMMENT 'Foreign key linking to compliance.permit. Business justification: Conservation practices (wetland restoration, filter strips, grassed waterways) often require Section 404 or NRCS permits. Linking conservation_practice to its governing permit enables permit condition',
    `purchase_order_id` BIGINT COMMENT 'Foreign key linking to procurement.purchase_order. Business justification: Conservation practice installations (tile drainage, waterways, cover crop establishment) are procured via purchase orders. Linking conservation_practice to its funding PO enables NRCS cost-share recon',
    `bmp_category` STRING COMMENT 'Best Management Practice (BMP) environmental category that this conservation practice addresses: soil_health, water_quality, nutrient_management, pest_management, wildlife habitat, or carbon_sequestration. Supports environmental stewardship reporting.. Valid values are `soil_health|water_quality|nutrient_management|pest_management|habitat|carbon_sequestration`',
    `carbon_credit_eligible` BOOLEAN COMMENT 'Indicates whether this conservation practice qualifies for carbon credit or greenhouse gas offset programs (e.g., cover crops, no-till, agroforestry) under ISCC or voluntary carbon market standards.',
    `certification_date` DATE COMMENT 'Date on which the conservation practice was officially certified as meeting USDA NRCS or program standards by the certifying agency.',
    `certifying_agency` STRING COMMENT 'Name of the agency or organization that certified the conservation practice as meeting applicable standards (e.g., USDA NRCS, state department of agriculture, third-party certifier, GLOBALG.A.P.).',
    `certifying_agent_name` STRING COMMENT 'Full name of the individual NRCS agent, conservation district employee, or third-party certifier who performed the practice certification inspection.',
    `cost_share_amount` DECIMAL(18,2) COMMENT 'Dollar amount of government cost-share payment received or approved for this conservation practice under the applicable USDA program. Expressed in USD.',
    `cost_share_contract_number` STRING COMMENT 'Official USDA NRCS or FSA contract number associated with the cost-share program agreement funding this conservation practice. Used for program compliance tracking and payment reconciliation.',
    `cost_share_program` STRING COMMENT 'USDA cost-share or incentive program funding this conservation practice: EQIP (Environmental Quality Incentives Program), CSP (Conservation Stewardship Program), RCPP (Regional Conservation Partnership Program), ACEP (Agricultural Conservation Easement Program), REAP (Rural Energy for America Program), or none for self-funded practices.. Valid values are `EQIP|CSP|RCPP|ACEP|REAP|none`',
    `county_code` STRING COMMENT 'Three-digit FIPS county code identifying the county where the conservation practice is located. Used for USDA NRCS county office routing and program administration.. Valid values are `^[0-9]{3}$`',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this conservation practice record was first created in the system, supporting data lineage, audit trail, and ISO 14001 environmental management documentation requirements.',
    `expiration_date` DATE COMMENT 'Date on which the conservation practice lifespan ends or the cost-share program contract expires, after which the practice status transitions to expired.',
    `fsma_compliant` BOOLEAN COMMENT 'Indicates whether this conservation practice supports compliance with the FDA Food Safety Modernization Act (FSMA) Produce Safety Rule requirements, particularly for water quality and soil amendment practices.',
    `gis_feature_code` STRING COMMENT 'Esri ArcGIS feature identifier linking this conservation practice record to its spatial geometry (polygon, polyline, or point) in the GIS layer for mapping and spatial analysis.',
    `installation_date` DATE COMMENT 'Date on which the conservation practice was physically installed or implemented on the field or parcel.',
    `iso14001_reference` STRING COMMENT 'Reference to the ISO 14001 Environmental Management System clause or environmental objective that this conservation practice supports (e.g., clause 6.1.2 Environmental Aspects, clause 8.1 Operational Planning).',
    `last_maintenance_date` DATE COMMENT 'Date of the most recent maintenance activity performed on this conservation practice to ensure continued effectiveness and compliance with NRCS practice standards.',
    `latitude` DECIMAL(18,2) COMMENT 'GPS latitude coordinate of the practice centroid or reference point in decimal degrees (WGS84), captured via RTK (Real-Time Kinematic) positioning for precision location tracking.',
    `longitude` DECIMAL(18,2) COMMENT 'GPS longitude coordinate of the practice centroid or reference point in decimal degrees (WGS84), captured via RTK (Real-Time Kinematic) positioning for precision location tracking.',
    `maintenance_required` BOOLEAN COMMENT 'Indicates whether this conservation practice requires scheduled maintenance activities (e.g., annual inspection, vegetation management, structural repair) to maintain its effectiveness and program compliance.',
    `next_maintenance_date` DATE COMMENT 'Scheduled date for the next required maintenance inspection or activity for this conservation practice, supporting proactive maintenance planning and program compliance.',
    `organic_program_eligible` BOOLEAN COMMENT 'Indicates whether this conservation practice is compatible with and supports USDA National Organic Program (NOP) certification requirements for organic production systems.',
    `planned_start_date` DATE COMMENT 'Scheduled start date for the conservation practice as agreed in the cost-share program contract or farm conservation plan.',
    `practice_area_acres` DECIMAL(18,2) COMMENT 'Total area covered by the conservation practice measured in acres. Used for area-based practices such as cover crops, filter strips, and nutrient management plans.',
    `practice_category` STRING COMMENT 'USDA NRCS classification category grouping the conservation practice by discipline: agronomy (soil/crop management), engineering (structural), forestry, range, or wildlife.. Valid values are `agronomy|engineering|forestry|range|wildlife`',
    `practice_code` STRING COMMENT 'Official USDA Natural Resources Conservation Service (NRCS) practice standard code identifying the type of conservation practice (e.g., 340 Cover Crop, 412 Grassed Waterway, 590 Nutrient Management, 393 Filter Strip, 484 Mulching).. Valid values are `^[0-9]{3}[A-Z]?$`',
    `practice_effectiveness_rating` STRING COMMENT 'Qualitative assessment of the conservation practice effectiveness in addressing the targeted resource concern, as evaluated during NRCS certification or periodic review (high, medium, low, not_evaluated).. Valid values are `high|medium|low|not_evaluated`',
    `practice_lifespan_years` STRING COMMENT 'Expected operational lifespan of the conservation practice in years as defined by USDA NRCS practice standards (e.g., cover crop annual, grassed waterway 10 years, terrace 25 years).',
    `practice_linear_feet` DECIMAL(18,2) COMMENT 'Length of the conservation practice measured in linear feet. Used for linear practices such as grassed waterways, filter strips, riparian buffers, and terraces.',
    `practice_name` STRING COMMENT 'Official USDA NRCS descriptive name of the conservation practice corresponding to the practice code (e.g., Cover Crop, Grassed Waterway, Nutrient Management Plan, Filter Strip).',
    `practice_notes` STRING COMMENT 'Free-text field for additional operational notes, site-specific conditions, deviations from standard specifications, or observations recorded during installation or certification of the conservation practice.',
    `practice_status` STRING COMMENT 'Current lifecycle status of the conservation practice: planned (approved but not yet installed), installed (physically implemented), certified (verified by certifying agency), expired (past lifespan or contract end), or cancelled (discontinued before completion).. Valid values are `planned|installed|certified|expired|cancelled`',
    `producer_cost` DECIMAL(18,2) COMMENT 'Net cost borne by the producer after deducting cost-share payments from total practice cost. Calculated as total_practice_cost minus cost_share_amount. Supports farm financial planning and CAPEX/OPEX reporting.',
    `resource_concern` STRING COMMENT 'USDA NRCS-defined resource concern that this conservation practice addresses (e.g., soil erosion by water, soil erosion by wind, excess nutrients in surface water, degraded plant condition). Aligns with NRCS Resource Concern Inventory.',
    `state_code` STRING COMMENT 'Two-letter US state abbreviation where the conservation practice is located, used for USDA NRCS state office routing, program eligibility, and regulatory reporting.. Valid values are `^[A-Z]{2}$`',
    `total_practice_cost` DECIMAL(18,2) COMMENT 'Total actual cost incurred to install and implement the conservation practice, including materials, labor, and equipment. Used to calculate net producer cost after cost-share payments.',
    `unit_of_measure` STRING COMMENT 'Unit of measure used to quantify the conservation practice extent (acres for area-based, linear_feet for linear structures, each for discrete installations, cubic_yards for earthwork, square_feet for small structures).. Valid values are `acres|linear_feet|each|cubic_yards|square_feet`',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent update to this conservation practice record, supporting audit trail, data lineage, and change tracking for program compliance reporting.',
    CONSTRAINT pk_conservation_practice PRIMARY KEY(`conservation_practice_id`)
) COMMENT 'Record of conservation and BMP (Best Management Practice) practices implemented on a field or parcel. Captures USDA NRCS practice code (e.g., 340 Cover Crop, 412 Grassed Waterway, 590 Nutrient Management), practice name, installation date, practice area (acres/linear feet), cost-share program (EQIP, CSP, RCPP), cost-share amount ($), practice lifespan (years), certification date, certifying agency, ISO 14001 environmental management reference, and practice status (planned/installed/certified/expired). Supports USDA NRCS program compliance and environmental stewardship reporting.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`land`.`irrigation_zone` (
    `irrigation_zone_id` BIGINT COMMENT 'Unique system-generated identifier for the irrigation zone or subsurface drainage zone record. Primary key for this entity.',
    `field_id` BIGINT COMMENT 'Reference to the agricultural field parcel to which this irrigation or drainage zone belongs. Provides spatial context linking the zone to its parent land unit.',
    `management_zone_id` BIGINT COMMENT 'Foreign key linking to land.management_zone. Business justification: An irrigation zone (water delivery and drainage infrastructure zone) frequently aligns with or is bounded by a management zone (soil-based VRA delineation). Linking irrigation_zone to management_zone ',
    `permit_id` BIGINT COMMENT 'Foreign key linking to compliance.permit. Business justification: Irrigation zones operate under water withdrawal permits. irrigation_zone.water_right_permit_ref is a denormalized reference to the governing permit. Linking to compliance.permit enables permit conditi',
    `water_right_id` BIGINT COMMENT 'Reference to the water right entitlement record governing the permitted water withdrawal volume for this irrigation zone. Supports regulatory compliance with state water authority permit requirements.',
    `zone_id` BIGINT COMMENT 'Foreign key linking to weather.weather_zone. Business justification: Irrigation scheduling systems apply ET normals and drought indices by weather zone. Linking irrigation_zone to weather_zone enables zone-level water balance calculations, drought-triggered irrigation ',
    `application_efficiency_pct` DECIMAL(18,2) COMMENT 'Ratio of water beneficially used by the crop to the total water applied by the irrigation system, expressed as a percentage. Key performance indicator for water use efficiency benchmarking against USDA NRCS and GLOBALG.A.P. standards.',
    `bmp_compliant` BOOLEAN COMMENT 'Indicates whether this irrigation or drainage zone is currently operating in compliance with applicable Best Management Practices (BMP) for water management as defined by USDA NRCS and state environmental agencies. Supports ISO 14001 environmental compliance reporting.',
    `conservation_practice_code` STRING COMMENT 'USDA NRCS Conservation Practice Standard code associated with this water management zone (e.g., 441 for Irrigation System, Microirrigation; 606 for Subsurface Drain). Used for EQIP (Environmental Quality Incentives Program) payment eligibility and conservation compliance reporting.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this irrigation zone record was first created in the system, in ISO 8601 format (yyyy-MM-ddTHH:mm:ss.SSSXXX). Supports data lineage, audit trail, and Silver Layer ingestion tracking in the Databricks Lakehouse.',
    `design_application_rate_in_hr` DECIMAL(18,2) COMMENT 'Engineered water application rate of the irrigation system expressed in inches per hour. Used to match application rate to soil infiltration capacity to prevent runoff and ensure uniform distribution. Sourced from system design specifications.',
    `drainage_area_acres` DECIMAL(18,2) COMMENT 'Total land area served by the subsurface tile drainage system in this zone, measured in acres. Used for drainage coefficient calculations, drainage district permit compliance, and BMP reporting. Applicable when zone_type = subsurface_drainage.',
    `drainage_coefficient_in_day` DECIMAL(18,2) COMMENT 'Design drainage rate of the subsurface tile system expressed in inches of water removed per day. Determines system capacity to handle peak rainfall events and maintain trafficable field conditions. Applicable when zone_type = subsurface_drainage.',
    `drainage_district_permit_ref` STRING COMMENT 'Permit number or reference code issued by the local drainage district authority governing the subsurface tile drainage system. Required for regulatory compliance and environmental reporting. Applicable when zone_type = subsurface_drainage.',
    `et_scheduling_enabled` BOOLEAN COMMENT 'Indicates whether this irrigation zone uses Evapotranspiration (ET)-based scheduling to determine irrigation timing and volume. ET-based scheduling integrates weather data and crop coefficients to optimize water use efficiency.',
    `gis_boundary_ref` STRING COMMENT 'Reference identifier or layer name for the zone boundary polygon stored in Esri ArcGIS. Enables spatial analysis, overlap detection, and RTK-accurate field mapping for precision water management.',
    `installation_contractor` STRING COMMENT 'Name of the contractor or company that installed the irrigation system or subsurface tile drainage system. Used for warranty claims, maintenance coordination, and capital expenditure (CAPEX) documentation.',
    `installation_cost_usd` DECIMAL(18,2) COMMENT 'Total capital expenditure (CAPEX) incurred for the installation of the irrigation or drainage system, expressed in US dollars. Used for asset valuation, depreciation calculations, and ROI analysis in SAP S/4HANA FI-AA and Granular Farm Management financial planning.',
    `installation_year` STRING COMMENT 'Calendar year in which the irrigation or drainage system was installed. Used for asset age tracking, depreciation scheduling, and infrastructure replacement planning in SAP S/4HANA Fixed Assets.',
    `irrigated_area_acres` DECIMAL(18,2) COMMENT 'Total land area served by this irrigation zone measured in acres. Used for permitted volume compliance calculations, water use efficiency reporting, and USDA Farm Service Agency (FSA) acreage reporting.',
    `last_inspection_date` DATE COMMENT 'Date of the most recent physical inspection of the irrigation or drainage system infrastructure. Used to track maintenance compliance intervals and trigger inspection work orders in SAP S/4HANA PM.',
    `notes` STRING COMMENT 'Free-text operational notes or remarks about the irrigation or drainage zone, including known issues, special operating conditions, or historical context not captured in structured fields. Used by farm managers and agronomists in Granular Farm Management.',
    `permitted_volume_acre_ft` DECIMAL(18,2) COMMENT 'Maximum annual water withdrawal volume authorized under the associated water right permit, expressed in acre-feet. Compliance ceiling for seasonal irrigation scheduling and water use reporting to state water authorities.',
    `soil_moisture_sensor_count` STRING COMMENT 'Number of soil moisture sensor locations deployed within this irrigation zone for real-time soil water status monitoring. Supports IoT-driven precision irrigation scheduling via John Deere Operations Center integration.',
    `soil_moisture_sensor_locations` STRING COMMENT 'GPS coordinate string or GIS reference describing the placement locations of soil moisture sensors within the zone (e.g., WKT MULTIPOINT or comma-separated lat/lon pairs). Supports precision water management and IoT sensor mapping in Esri ArcGIS.',
    `system_condition` STRING COMMENT 'Current physical condition assessment of the irrigation or drainage infrastructure. Drives maintenance prioritization, capital replacement planning, and OEE reporting in SAP S/4HANA PM and John Deere Operations Center.. Valid values are `good|fair|poor`',
    `system_type` STRING COMMENT 'Classification of the irrigation delivery system technology installed in this zone. Determines application efficiency benchmarks, scheduling parameters, and maintenance requirements. Applicable when zone_type = irrigation. [ENUM-REF-CANDIDATE: center_pivot|drip|flood|subsurface_drip|linear_move|traveling_gun — promote to reference product if additional types are needed]. Valid values are `center_pivot|drip|flood|subsurface_drip|linear_move|traveling_gun`',
    `tile_depth_inches` DECIMAL(18,2) COMMENT 'Installation depth of the subsurface drainage tile below the soil surface in inches. Affects drainage effectiveness, frost protection, and interaction with soil horizons. Applicable when zone_type = subsurface_drainage.',
    `tile_diameter_inches` DECIMAL(18,2) COMMENT 'Internal diameter of the subsurface drainage tile pipe in inches. Determines hydraulic capacity and drainage coefficient. Used for system capacity calculations and replacement planning. Applicable when zone_type = subsurface_drainage.',
    `tile_map_gis_ref` STRING COMMENT 'Reference identifier or layer name for the subsurface tile drainage map stored in Esri ArcGIS. Enables spatial visualization of tile layout, outlet locations, and drainage area boundaries for BMP planning and contractor coordination.',
    `tile_material` STRING COMMENT 'Material composition of the subsurface drainage tile pipe installed in this zone. Corrugated plastic/HDPE is the modern standard; clay and concrete are legacy materials found in older installations. Applicable when zone_type = subsurface_drainage.. Valid values are `clay|concrete|hdpe`',
    `tile_outlet_latitude` DECIMAL(18,2) COMMENT 'GPS latitude coordinate of the subsurface tile drainage system outlet location in decimal degrees (WGS84). Used for field mapping in Esri ArcGIS and environmental monitoring of drainage discharge points. Applicable when zone_type = subsurface_drainage.',
    `tile_outlet_longitude` DECIMAL(18,2) COMMENT 'GPS longitude coordinate of the subsurface tile drainage system outlet location in decimal degrees (WGS84). Used for field mapping in Esri ArcGIS and environmental monitoring of drainage discharge points. Applicable when zone_type = subsurface_drainage.',
    `tile_system_type` STRING COMMENT 'Classification of the subsurface tile drainage system layout installed in this zone. Pattern indicates systematic grid installation; random indicates targeted placement in wet spots; interceptor indicates placement to intercept lateral water flow. Applicable when zone_type = subsurface_drainage.. Valid values are `pattern|random|interceptor`',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent modification to this irrigation zone record, in ISO 8601 format (yyyy-MM-ddTHH:mm:ss.SSSXXX). Supports change data capture (CDC), audit compliance, and Silver Layer delta processing in the Databricks Lakehouse.',
    `water_source_type` STRING COMMENT 'Classification of the primary water supply source feeding this irrigation zone (e.g., groundwater well, surface river diversion, on-farm reservoir, irrigation canal). Critical for water right compliance and drought risk assessment. [ENUM-REF-CANDIDATE: well|river|reservoir|canal|municipal|recycled — promote to reference product if additional sources are needed]. Valid values are `well|river|reservoir|canal|municipal|recycled`',
    `zone_status` STRING COMMENT 'Current operational lifecycle status of the irrigation or drainage zone. Drives scheduling eligibility, maintenance planning, and asset reporting in SAP S/4HANA PM and John Deere Operations Center.. Valid values are `active|inactive|decommissioned|under_construction|seasonal`',
    `zone_type` STRING COMMENT 'Discriminator indicating whether this zone record represents an irrigation delivery system or a subsurface tile drainage system. Drives which set of operational attributes are applicable for the zone.. Valid values are `irrigation|subsurface_drainage`',
    CONSTRAINT pk_irrigation_zone PRIMARY KEY(`irrigation_zone_id`)
) COMMENT 'Spatial and operational record for all field-level water management infrastructure — the single source of truth for both irrigation delivery systems and subsurface tile drainage systems within a field. For irrigation: captures zone name, system type (center pivot, drip, flood, subsurface drip, linear move, traveling gun), water source (well, river, reservoir, canal), water right permit reference, permitted volume (acre-feet), irrigated acres, application efficiency (%), design application rate (in/hr), soil moisture sensor locations, and ET-based scheduling parameters. For subsurface drainage: captures tile system type (pattern, random, interceptor), tile material (clay, concrete, corrugated plastic/HDPE), tile diameter (inches), tile depth (inches), outlet location GPS, drainage area (acres), drainage coefficient (inches/day), tile map GIS reference, installation contractor, installation year, estimated cost, system condition (good/fair/poor), and drainage district permit reference. Integrates with John Deere Operations Center for precision water management. Links to field for spatial context and to water_right for entitlement compliance. SSOT for all field-level water infrastructure including both irrigation and drainage.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`land`.`farm_unit` (
    `farm_unit_id` BIGINT COMMENT 'Unique surrogate identifier for the farm unit record in the land domain. Primary key for the farm_unit entity, serving as the top-level aggregation point in the land domain hierarchy (farm_unit → parcel → field).',
    `account_id` BIGINT COMMENT 'Foreign key linking to customer.account. Business justification: Farm units are operated by legal entities that are customer accounts. Agronomic service contracts, input supply agreements, FSA program enrollment, and crop marketing contracts all require linking the',
    `commodity_id` BIGINT COMMENT 'Foreign key linking to product.commodity. Business justification: FSA Farm Registration and crop insurance unit classification require farm units to reference the commodity master for their primary commodity. primary_commodity is a denormalized text field; a domain ',
    `employee_id` BIGINT COMMENT 'Foreign key linking to workforce.employee. Business justification: Farm managers are employees; the denormalized farm_manager_name text field should be replaced with a proper FK to employee for org chart reporting, manager accountability, performance management, and ',
    `zone_id` BIGINT COMMENT 'Foreign key linking to weather.weather_zone. Business justification: Farm-level climate risk reporting, USDA program enrollment, and crop insurance unit assignments require weather zone classification at the farm_unit level. Ag operations managers expect farm units to ',
    `clu_identifier` STRING COMMENT 'USDA FSA Common Land Unit (CLU) identifier linking this farm unit to the official USDA geospatial land unit registry. CLU is the smallest unit of land with a permanent, contiguous boundary used for FSA program administration and acreage reporting.',
    `conservation_program_enrollment` STRING COMMENT 'Name or code of USDA conservation programs in which this farm unit is enrolled (e.g., CRP, EQIP, CSP, RCPP). Supports BMP compliance tracking, conservation payment eligibility, and ISO 14001 environmental management reporting.',
    `country_code` STRING COMMENT 'ISO 3166-1 alpha-3 country code for the country in which this farm unit operates (e.g., USA, CAN, BRA). Supports international operations, COOL (Country of Origin Labeling) compliance, and multi-country enterprise reporting.. Valid values are `^[A-Z]{3}$`',
    `county_name` STRING COMMENT 'Name of the county in which the majority of this farm units land is located. Required for FSA county office assignment, crop insurance county-level rate determination, and USDA program administration.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this farm unit record was first created in the system. Supports data lineage, audit trail requirements, and SOX financial reporting controls.',
    `crop_insurance_unit_number` STRING COMMENT 'Risk Management Agency (RMA) assigned crop insurance unit number linking this farm unit to its crop insurance policy structure. Used for indemnity calculations, acreage reporting, and production history tracking under USDA RMA programs.',
    `effective_end_date` DATE COMMENT 'Date on which this farm unit ceased operations or was retired from active management. Null for currently active farm units. Used for historical reporting, FSA record archival, and enterprise lifecycle management.',
    `effective_start_date` DATE COMMENT 'Date on which this farm unit became operationally active and eligible for FSA program enrollment, crop insurance, and enterprise management. Marks the beginning of the farm units operational lifecycle.',
    `erp_cost_center_code` STRING COMMENT 'SAP S/4HANA CO module cost center code assigned to this farm unit for enterprise financial management, OPEX/CAPEX allocation, and profitability analysis. Links farm unit operations to the general ledger for enterprise budgeting.',
    `erp_profit_center_code` STRING COMMENT 'SAP S/4HANA CO module profit center code for this farm unit, enabling enterprise-level profitability analysis, EBITDA reporting, and ROI tracking at the farm unit level.',
    `farm_type` STRING COMMENT 'Classification of the farm unit by primary production system. Drives enterprise budgeting templates, crop insurance unit structuring, and FSA program eligibility. [ENUM-REF-CANDIDATE: grain|livestock|mixed|specialty_crop|orchard|vegetable|aquaculture|dairy|poultry — promote to reference product if additional types are needed]. Valid values are `grain|livestock|mixed|specialty_crop|orchard|vegetable`',
    `farm_unit_name` STRING COMMENT 'Human-readable name assigned to the farm unit, typically reflecting the operating entity or geographic identity of the farm (e.g., Sunrise Grain Farm, Heartland Livestock Unit). Used in reporting, FSA program enrollment, and enterprise budgeting.',
    `fmis_reference_code` STRING COMMENT 'External reference identifier for this farm unit in the Farm Management Information System (FMIS), such as Granular Farm Management or Climate FieldView. Enables cross-system data integration and operational data lineage tracking.',
    `fsa_county_code` STRING COMMENT 'USDA FSA numeric county code for the county office administering this farm unit. Combined with FSA state code and farm number to form the complete FSA farm identifier for program enrollment and payment tracking.. Valid values are `^[0-9]{3}$`',
    `fsa_farm_number` STRING COMMENT 'USDA Farm Service Agency (FSA) assigned farm number uniquely identifying this farm unit within the FSA county office system. Required for FSA program enrollment, crop insurance unit structuring, and USDA program payment tracking.. Valid values are `^[0-9]{1,7}$`',
    `fsa_state_code` STRING COMMENT 'USDA FSA numeric state code assigned to the state where this farm unit is registered. Used in conjunction with FSA county code and farm number for unique FSA record identification and program payment routing.. Valid values are `^[0-9]{2}$`',
    `fsa_tract_number` STRING COMMENT 'USDA FSA tract number associated with this farm unit, identifying the contiguous block of land under common ownership or control within the FSA farm. Used for FSA program eligibility, acreage reporting, and USDA payment calculations.. Valid values are `^[0-9]{1,7}$`',
    `gis_boundary_reference` STRING COMMENT 'Reference identifier or URL to the GIS polygon boundary layer for this farm unit in Esri ArcGIS or John Deere Operations Center. Enables RTK-accurate field mapping, GPS positioning, and spatial analytics for precision agriculture applications.',
    `globalg_ap_number` STRING COMMENT 'GLOBALG.A.P. certification number assigned to this farm unit, confirming compliance with global Good Agricultural Practices (GAP) standards. Required for export market access and retail supply chain qualification.',
    `irrigation_type` STRING COMMENT 'Primary irrigation method employed on this farm unit. Informs water resource management planning, evapotranspiration (ET) calculations, water use efficiency reporting, and USDA conservation program eligibility.. Valid values are `drip|sprinkler|flood|center_pivot|subsurface|none`',
    `latitude` DECIMAL(18,2) COMMENT 'Geographic latitude coordinate (decimal degrees, WGS84) of the farm units centroid or primary reference point. Supports GIS mapping, GPS navigation, precision agriculture applications, and spatial analytics in Esri ArcGIS.',
    `leased_acres` DECIMAL(18,2) COMMENT 'Total acres of land under cash rent or crop share lease agreements within this farm unit. Supports OPEX planning, lease liability reporting under IFRS 16/ASC 842, and FSA program eligibility determination.',
    `longitude` DECIMAL(18,2) COMMENT 'Geographic longitude coordinate (decimal degrees, WGS84) of the farm units centroid or primary reference point. Supports GIS mapping, GPS navigation, precision agriculture applications, and spatial analytics in Esri ArcGIS.',
    `notes` STRING COMMENT 'Free-text field for operational notes, special conditions, or contextual information about this farm unit not captured in structured fields. Used by farm managers and data stewards for supplemental documentation.',
    `operational_status` STRING COMMENT 'Current lifecycle status of the farm unit indicating whether it is actively managed, temporarily inactive, under transition (e.g., organic conversion), or permanently retired from operation.. Valid values are `active|inactive|suspended|transitional|retired`',
    `organic_certification_status` STRING COMMENT 'Current USDA National Organic Program (NOP) certification status of the farm unit. Drives premium pricing, market channel eligibility, input restrictions, and compliance reporting requirements under USDA NOP regulations.. Valid values are `certified|transitional|conventional|exempt`',
    `owned_acres` DECIMAL(18,2) COMMENT 'Total acres of land owned outright by the operating entity within this farm unit. Supports land asset valuation, CAPEX planning, and differentiation from leased land in enterprise financial reporting.',
    `primary_watershed` STRING COMMENT 'Name or HUC (Hydrologic Unit Code) of the primary watershed in which this farm unit is located. Used for EPA water quality compliance, BMP planning, conservation program eligibility, and environmental monitoring under ISO 14001.',
    `state_code` STRING COMMENT 'Two-letter US state abbreviation (USPS standard) for the state in which this farm unit is primarily located. Used for FSA state office routing, state-level regulatory compliance, and geographic reporting.. Valid values are `^[A-Z]{2}$`',
    `tillage_practice` STRING COMMENT 'Predominant tillage practice employed on this farm unit. Supports soil health management, carbon sequestration reporting, BMP compliance, and USDA conservation program eligibility assessments.. Valid values are `no_till|reduced_till|conventional_till|strip_till`',
    `total_operated_acres` DECIMAL(18,2) COMMENT 'Total land area operated by this farm unit in acres, encompassing both owned and leased parcels. Used for FSA acreage reporting, crop insurance unit sizing, enterprise budgeting, and USDA program payment calculations.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this farm unit record was last modified. Supports change tracking, data lineage, and audit trail requirements for FSA program compliance and SOX financial reporting controls.',
    CONSTRAINT pk_farm_unit PRIMARY KEY(`farm_unit_id`)
) COMMENT 'Operational farm unit grouping fields and parcels under a single management structure — typically corresponding to a USDA FSA farm number and tract number. Captures farm name, FSA farm number, FSA tract number, operating entity name, farm manager, total operated acres (owned + leased), county, state, primary commodity, farm type (grain, livestock, mixed, specialty crop), and operational status (active/inactive). Serves as the top-level aggregation point in the land domain hierarchy: farm_unit → parcel → field. Links to parcels for legal land identity and to fields for operational management. Used for FSA program enrollment, crop insurance unit structuring, enterprise budgeting, and USDA program payment tracking. One farm_unit may span multiple parcels and contain multiple fields. SSOT for the operational hierarchy that links fields and parcels to their managing entity.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`land`.`easement` (
    `easement_id` BIGINT COMMENT 'Unique system-generated identifier for the easement record. Primary key for the land.easement data product.',
    `obligation_id` BIGINT COMMENT 'Foreign key linking to compliance.compliance_obligation. Business justification: Conservation easements create long-term compliance obligations (annual monitoring requirements, restricted use obligations, reporting to land trusts). Linking easement to its governing compliance obli',
    `parcel_id` BIGINT COMMENT 'Reference to the land parcel on which this easement is recorded. Links to the parcel master record in the land domain.',
    `permit_id` BIGINT COMMENT 'Foreign key linking to compliance.permit. Business justification: Conservation easements may require environmental permits (Section 404 wetland permits, NRCS easement permits). Linking easement to the governing permit enables compliance tracking for easement-related',
    `annual_payment` DECIMAL(18,2) COMMENT 'Annual recurring payment made to the grantor for the easement right, expressed in US dollars. Applicable for term easements with periodic compensation structures. Used for OPEX budgeting and financial planning in Granular Farm Management.',
    `area_acres` DECIMAL(18,2) COMMENT 'Total land area encumbered by the easement, measured in acres. Applicable for area-based easements such as conservation easements or drainage easements. May be null for linear corridor easements defined by width and length.',
    `compensation_amount` DECIMAL(18,2) COMMENT 'Total monetary compensation paid to the grantor (landowner) for granting the easement rights, expressed in US dollars. Includes one-time payments and the present value of any annualized payments. Relevant for CAPEX tracking and land asset valuation.',
    `conservation_program` STRING COMMENT 'Name of the USDA or government conservation program under which the easement was established, if applicable. Examples include ACEP (Agricultural Conservation Easement Program), WRP (Wetland Reserve Program), or RCPP (Regional Conservation Partnership Program). Null if not a conservation easement.',
    `corridor_width_ft` DECIMAL(18,2) COMMENT 'Width of the easement corridor in feet, applicable for linear easements such as utility rights-of-way, pipeline easements, and road access corridors. Used in conjunction with easement_length_ft to calculate the encumbered area.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when the easement record was first created in the system. Supports data lineage, audit trail, and Silver Layer ingestion tracking in the Databricks Lakehouse.',
    `document_reference` STRING COMMENT 'Official recorded document reference number including book, page, instrument number, or deed reference as assigned by the county recorder or land registry. Used for title searches and legal due diligence.',
    `easement_number` STRING COMMENT 'Externally-known document or instrument number assigned by the county recorder or title company at the time of recording. Used for title due diligence and cross-referencing recorded documents.',
    `easement_status` STRING COMMENT 'Current lifecycle status of the easement. Active indicates the easement is in force; expired indicates the term has lapsed; terminated indicates early legal termination; pending indicates recorded but not yet effective; suspended indicates temporarily inactive due to legal dispute or review.. Valid values are `active|expired|terminated|pending|suspended`',
    `easement_type` STRING COMMENT 'Classification of the easement by its legal purpose. Common types include right-of-way (road/rail corridor), utility (power/telecom lines), drainage (water flow), conservation (land preservation), access (ingress/egress), and pipeline (oil/gas/water). [ENUM-REF-CANDIDATE: right_of_way|utility|drainage|conservation|access|pipeline|irrigation|flood_control|scenic|agricultural_preservation — promote to reference product]. Valid values are `right_of_way|utility|drainage|conservation|access|pipeline`',
    `effective_date` DATE COMMENT 'Date on which the easement rights become legally binding and enforceable. May differ from the recording date if the instrument specifies a future commencement date.',
    `environmental_review_required` BOOLEAN COMMENT 'Indicates whether an environmental impact review or assessment is required for activities within or adjacent to the easement area. True = environmental review required per EPA or state agency mandate; False = no review required.',
    `expiration_date` DATE COMMENT 'Date on which a term easement expires and the rights revert to the landowner. Null for perpetual easements. Critical for land use planning and lease renewal workflows.',
    `gis_geometry_ref` STRING COMMENT 'Reference identifier linking to the easement boundary geometry stored in Esri ArcGIS. Enables spatial analysis, field mapping, and RTK-accurate boundary visualization in the John Deere Operations Center and ArcGIS GIS platform.',
    `gis_layer_name` STRING COMMENT 'Name of the ArcGIS feature layer or map service layer containing the easement geometry. Used to locate and render the easement boundary in GIS-based land use planning and environmental monitoring workflows.',
    `grantee_name` STRING COMMENT 'Full legal name of the party receiving the easement right — typically a utility company, government agency, neighboring landowner, or conservation organization. Required for title due diligence and regulatory compliance.',
    `grantee_type` STRING COMMENT 'Classification of the grantee entity receiving the easement right. Supports analytics on easement exposure by counterparty category and regulatory reporting. [ENUM-REF-CANDIDATE: utility_company|government_agency|neighbor|conservation_org|railroad|pipeline_company|irrigation_district|municipality — promote to reference product]. Valid values are `utility_company|government_agency|neighbor|conservation_org|railroad`',
    `grantor_name` STRING COMMENT 'Full legal name of the party granting the easement right — typically the landowner or agricultural operator who owns the burdened parcel. Required for title due diligence and legal enforceability.',
    `is_perpetual` BOOLEAN COMMENT 'Indicates whether the easement is perpetual (no expiration date) or term-limited. True = perpetual easement with no expiration; False = term easement with a defined expiration date.',
    `last_monitored_date` DATE COMMENT 'Date of the most recent stewardship monitoring visit or compliance inspection conducted on the easement area. Required for conservation easement compliance reporting to USDA NRCS and GFSI certification bodies.',
    `legal_description` STRING COMMENT 'Formal legal description of the easement area as recorded in the deed or instrument, using metes and bounds, lot/block, or Public Land Survey System (PLSS) section-township-range notation. Required for title due diligence and legal enforceability.',
    `length_ft` DECIMAL(18,2) COMMENT 'Total linear length of the easement corridor in feet. Used for linear easements such as utility lines, pipelines, and road rights-of-way. Combined with corridor_width_ft to determine total encumbered area.',
    `notes` STRING COMMENT 'Free-text field for additional operational notes, legal commentary, or land management observations related to the easement. Used by land managers and legal counsel for context not captured in structured fields.',
    `permitted_uses` STRING COMMENT 'Narrative description of land uses explicitly permitted within the easement area by the grantor. May include grazing, crop production, or recreational access where not restricted by the easement terms. Supports land use planning and compliance audits.',
    `recording_county` STRING COMMENT 'Name of the county or jurisdiction where the easement instrument was officially recorded. Required for title due diligence and regulatory compliance reporting.',
    `recording_date` DATE COMMENT 'Date the easement instrument was officially recorded with the county recorder or relevant land registry authority. Establishes the legal priority and effective date of the encumbrance.',
    `recording_state` STRING COMMENT 'Two-letter US state code (e.g., IA, IL, KS) where the easement instrument was recorded. Used for jurisdictional compliance and regulatory reporting to USDA, EPA, and state agricultural agencies.',
    `restrictions_description` STRING COMMENT 'Narrative description of land use restrictions imposed by the easement on the grantors parcel. Includes prohibited activities such as construction, tillage, chemical application, or tree removal within the easement corridor. Critical for crop planning, BMP compliance, and GLOBALG.A.P. certification.',
    `review_date` DATE COMMENT 'Scheduled date for the next periodic review or monitoring inspection of the easement, particularly for conservation easements requiring annual stewardship monitoring per USDA NRCS requirements.',
    `source_system` STRING COMMENT 'Operational system of record from which this easement record originated. Supports data lineage and integration traceability across Esri ArcGIS, Granular Farm Management, Oracle NetSuite, or manual entry workflows.. Valid values are `ArcGIS|Granular|NetSuite|Manual`',
    `termination_date` DATE COMMENT 'Actual date on which the easement was legally terminated, released, or extinguished prior to or at its natural expiration. Distinct from expiration_date which is the scheduled end date. Null if the easement is still active.',
    `termination_reason` STRING COMMENT 'Reason for the termination or expiration of the easement. Applicable only when easement_status is terminated or expired. Values include expired (natural term end), released (voluntary release by grantee), condemned (eminent domain), merged (unity of ownership), or court_order (judicial termination).. Valid values are `expired|released|condemned|merged|court_order`',
    `title_insurance_policy` STRING COMMENT 'Policy number of the title insurance policy that covers this easement encumbrance. Used for risk management, title due diligence, and insurance claims processing.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when the easement record was most recently modified. Supports change data capture (CDC), audit trail, and data quality monitoring in the Databricks Lakehouse Silver Layer.',
    `violation_description` STRING COMMENT 'Narrative description of any identified easement violation or encroachment, including the nature of the violation, date discovered, and current remediation status. Populated only when violation_flag is True.',
    `violation_flag` BOOLEAN COMMENT 'Indicates whether an active easement violation or encroachment has been identified on this easement. True = violation or encroachment currently under investigation or remediation; False = no known violation.',
    CONSTRAINT pk_easement PRIMARY KEY(`easement_id`)
) COMMENT 'Legal easement and encumbrance record for parcels — capturing rights-of-way, utility easements, drainage easements, conservation easements, and access agreements that affect land use. Stores easement type, grantor name, grantee name (utility company, government agency, neighbor), easement area (acres) or corridor width (feet), easement length (feet), recorded document reference, recording date, expiration date (if term easement), compensation paid ($), restrictions imposed, and GIS geometry reference. Critical for land use planning and title due diligence.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`land`.`water_right` (
    `water_right_id` BIGINT COMMENT 'Unique system-generated surrogate identifier for the water right record. Primary key for the water_right data product in the land domain.',
    `account_id` BIGINT COMMENT 'Foreign key linking to customer.account. Business justification: Water rights are held by legal entities (accounts). Water right transfers, annual use reporting to state agencies, and curtailment notifications are directed to the holder account. Water rights can be',
    `parcel_id` BIGINT COMMENT 'Reference to the land parcel or farm unit to which this water right is appurtenant or associated. Links the water entitlement to the physical land asset.',
    `zone_id` BIGINT COMMENT 'Foreign key linking to weather.weather_zone. Business justification: State water agencies use climate zone classifications to administer curtailment decisions during drought. Linking water_right to weather_zone enables drought index monitoring against permitted water r',
    `annual_use_report_required` BOOLEAN COMMENT 'Indicates whether the permit requires submission of an annual water use report to the issuing regulatory agency. True if mandatory reporting is required; False otherwise. Drives compliance calendar and reporting workflow.',
    `annual_volume_acre_feet` DECIMAL(18,2) COMMENT 'Maximum volume of water authorized for diversion or extraction per calendar or water year, expressed in acre-feet. One acre-foot equals approximately 325,851 US gallons. This is the primary volumetric entitlement cap for compliance and water budget planning.',
    `aquifer_name` STRING COMMENT 'Name or designation of the groundwater aquifer from which extraction is authorized. Applicable for groundwater rights only. Used for aquifer management, depletion tracking, and state groundwater conservation district compliance.',
    `certificate_document_ref` STRING COMMENT 'Document management system reference or file path to the scanned water right certificate, permit, or decree. Enables retrieval of the original legal instrument for audit, compliance, and due diligence purposes.',
    `curtailment_effective_date` DATE COMMENT 'The date on which the current curtailment order became effective. Null if no curtailment is in effect. Used for operational planning and water supply risk management.',
    `curtailment_status` STRING COMMENT 'Current curtailment status indicating whether the regulatory authority has restricted or reduced authorized diversions due to drought, shortage, or senior right priority calls. Not_curtailed means full use is authorized; curtailed means diversion is prohibited; partially_curtailed means reduced diversion is allowed.. Valid values are `not_curtailed|curtailed|partially_curtailed`',
    `flow_rate_cfs` DECIMAL(18,2) COMMENT 'Maximum instantaneous diversion or extraction rate authorized under the water right, expressed in cubic feet per second (CFS). Governs the rate of water withdrawal at any given moment, distinct from the annual volume cap.',
    `flow_rate_gpm` DECIMAL(18,2) COMMENT 'Maximum instantaneous diversion or extraction rate expressed in gallons per minute (GPM). Commonly used for groundwater well permits and pump specifications. Complements the CFS measure for operational pump management.',
    `holder_type` STRING COMMENT 'Legal entity classification of the water right holder. Determines applicable regulatory requirements, reporting obligations, and transfer restrictions under state water law.. Valid values are `individual|corporation|partnership|government|cooperative|trust`',
    `irrigated_acres` DECIMAL(18,2) COMMENT 'Total acreage authorized for irrigation under this water right. Defines the maximum land area that may receive water from this entitlement. Used for water use efficiency calculations and USDA farm program compliance.',
    `is_adjudicated` BOOLEAN COMMENT 'Indicates whether this water right has been formally adjudicated (confirmed by a court or administrative proceeding) as part of a general stream adjudication. Adjudicated rights have legally confirmed priority and volume.',
    `is_transferable` BOOLEAN COMMENT 'Indicates whether this water right may be legally transferred, sold, or leased to another party under applicable state water law. True if transferable; False if appurtenant to the land and non-transferable.',
    `issuing_agency` STRING COMMENT 'Name of the governmental or regulatory authority that issued the water right permit or certificate (e.g., State Engineers Office, State Water Resources Control Board, Bureau of Reclamation). Required for regulatory correspondence and compliance reporting.',
    `issuing_state` STRING COMMENT 'Two-letter US state code of the jurisdiction that issued the water right. Determines the applicable state water law doctrine (prior appropriation vs. riparian) and regulatory framework.. Valid values are `^[A-Z]{2}$`',
    `last_use_report_date` DATE COMMENT 'Date on which the most recent annual water use report was submitted to the regulatory agency. Used to track reporting compliance and identify overdue filings.',
    `notes` STRING COMMENT 'Free-text field for additional legal conditions, special permit stipulations, environmental mitigation requirements, or operational notes associated with this water right that are not captured in structured fields.',
    `permit_expiry_date` DATE COMMENT 'The date on which the water permit or certificate expires and must be renewed. Null for perpetual rights. Used for compliance calendar management and renewal workflow triggers.',
    `permit_issue_date` DATE COMMENT 'The date on which the water permit or certificate was officially issued by the issuing regulatory agency. May differ from the priority date in appropriative systems.',
    `permit_number` STRING COMMENT 'Externally-issued permit or certificate number assigned by the state water resource agency or regulatory authority. Serves as the official legal identifier for the water right on regulatory filings and compliance documentation.',
    `permitted_use` STRING COMMENT 'The authorized beneficial use category for which the water right was granted. Irrigation covers crop and field watering; livestock covers animal husbandry water supply; domestic covers on-farm household use; municipal, industrial, and recreational uses apply where applicable. Use must match actual application for compliance. [ENUM-REF-CANDIDATE: irrigation|livestock|domestic|municipal|industrial|recreational|aquaculture|dust_suppression — promote to reference product if additional uses are needed]. Valid values are `irrigation|livestock|domestic|municipal|industrial|recreational`',
    `place_of_use_description` STRING COMMENT 'Legal description or narrative of the authorized place(s) where diverted or extracted water may be beneficially used. May reference legal land descriptions (township, range, section) or parcel identifiers. Restricts where water can be applied under the permit.',
    `point_of_diversion_lat` DECIMAL(18,2) COMMENT 'GPS latitude coordinate (decimal degrees, WGS84) of the authorized point of diversion or extraction. Required for regulatory mapping, GIS integration with Esri ArcGIS, and field verification of diversion infrastructure.',
    `point_of_diversion_lon` DECIMAL(18,2) COMMENT 'GPS longitude coordinate (decimal degrees, WGS84) of the authorized point of diversion or extraction. Required for regulatory mapping, GIS integration with Esri ArcGIS, and field verification of diversion infrastructure.',
    `previous_holder_name` STRING COMMENT 'Name of the entity or individual from whom this water right was most recently transferred. Supports chain-of-title documentation and transfer history for regulatory compliance.',
    `priority_date` DATE COMMENT 'The legally established date that determines the seniority of this water right relative to other rights on the same water source. Under prior appropriation doctrine, earlier priority dates have superior claim during shortage conditions. Critical for western-state water allocation compliance.',
    `record_created_timestamp` TIMESTAMP COMMENT 'The date and time when this water right record was first created in the system. Supports data lineage, audit trail, and Silver layer ingestion tracking in the Databricks Lakehouse.',
    `record_updated_timestamp` TIMESTAMP COMMENT 'The date and time when this water right record was most recently modified. Supports change detection, incremental processing, and audit trail requirements in the Databricks Lakehouse Silver layer.',
    `right_type` STRING COMMENT 'Legal classification of the water right doctrine under which the entitlement is held. Surface rights derive from surface water bodies; groundwater rights pertain to aquifer extraction; riparian rights attach to land adjacent to a water body; appropriative rights follow prior appropriation doctrine (first-in-time, first-in-right) common in western US states; prescriptive rights arise from long-term use. [ENUM-REF-CANDIDATE: surface|groundwater|riparian|appropriative|prescriptive|adjudicated — promote to reference product if additional types are needed]. Valid values are `surface|groundwater|riparian|appropriative|prescriptive`',
    `season_end_date` DATE COMMENT 'The calendar date on which authorized water diversion or use must cease each year under seasonal restrictions of the permit. Null if the right has no seasonal restriction.',
    `season_start_date` DATE COMMENT 'The calendar date on which authorized water diversion or use may begin each year under seasonal restrictions of the permit. Null if the right has no seasonal restriction.',
    `source_water_body` STRING COMMENT 'Name of the surface water body (river, stream, canal, reservoir, lake) or groundwater basin from which water is authorized to be diverted or extracted. Required for source identification in regulatory filings and environmental monitoring.',
    `source_water_body_type` STRING COMMENT 'Classification of the water source type. Distinguishes surface water sources (river, stream, canal, reservoir, lake, spring) from groundwater sources (aquifer) for regulatory categorization and environmental impact assessment. [ENUM-REF-CANDIDATE: river|stream|canal|reservoir|lake|spring|aquifer — 7 candidates stripped; promote to reference product]',
    `transfer_date` DATE COMMENT 'The date on which ownership or appurtenance of this water right was most recently transferred to the current holder. Null if no transfer has occurred. Supports transfer history tracking and chain-of-title documentation.',
    `water_district` STRING COMMENT 'Name of the irrigation district, water conservation district, or water management area within which this water right is administered. Relevant for district-level allocation, assessment fees, and delivery scheduling.',
    `water_right_status` STRING COMMENT 'Current lifecycle status of the water right. Active indicates the right is valid and in use; inactive indicates the right is held but not currently exercised; transferred indicates ownership or appurtenance has changed; forfeited indicates the right has been lost due to non-use or regulatory action; suspended indicates temporary regulatory hold.. Valid values are `active|inactive|transferred|forfeited|suspended`',
    `well_depth_ft` DECIMAL(18,2) COMMENT 'Total drilled depth of the extraction well in feet below ground surface. Applicable for groundwater rights. Used for aquifer characterization, pump sizing, and regulatory well construction compliance.',
    `well_registration_number` STRING COMMENT 'Official registration or permit number assigned to the extraction well by the state well permitting authority. Applicable for groundwater rights. Links the water right to the physical well infrastructure for compliance and inspection records.',
    CONSTRAINT pk_water_right PRIMARY KEY(`water_right_id`)
) COMMENT 'Legal water right and permit record documenting authorized water use entitlements associated with parcels or farm units. Captures permit number, issuing agency, priority date, right type (surface, groundwater, riparian, appropriative), permitted use, volume (acre-feet/year), flow rate (CFS/GPM), source water body, well registration, aquifer, status (active/inactive/transferred/forfeited), and transfer history. SSOT for water entitlement compliance — critical for western-state prior appropriation doctrine and state water resource regulation.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`land`.`farm_vendor_approval` (
    `farm_vendor_approval_id` BIGINT COMMENT 'Primary key for the farm_vendor_approval association',
    `farm_unit_id` BIGINT COMMENT 'Foreign key linking this vendor approval record to the specific farm unit for which the vendor is authorized to supply inputs.',
    `vendor_id` BIGINT COMMENT 'Foreign key linking this vendor approval record to the approved vendor in the procurement vendor master.',
    `approval_status` STRING COMMENT 'Current lifecycle status of this farm-unit vendor approval. Drives procurement eligibility checks when generating purchase orders for this farm unit.',
    `approved_input_categories` STRING COMMENT 'Comma-delimited list of agricultural input categories this vendor is approved to supply specifically to this farm unit. Distinct from the vendor-level approved_input_categories on the vendor master, as a vendor may be approved for a subset of categories at a given farm unit.',
    `effective_date` DATE COMMENT 'Date on which this vendor approval became active and the vendor became eligible to supply inputs to this farm unit. Marks the start of the approval validity window.',
    `expiration_date` DATE COMMENT 'Date on which this vendor approval expires and must be renewed or allowed to lapse. Procurement systems should block new purchase orders against this farm-vendor combination after this date.',
    `farm_specific_pricing` STRING COMMENT 'Reference identifier or description of the farm-unit-level pricing agreement negotiated with this vendor, distinct from the vendors standard pricing. May reference a contract number, price schedule code, or volume discount tier applicable only to this farm unit.',
    `preferred_status` BOOLEAN COMMENT 'Indicates whether this vendor holds preferred supplier status for the associated farm unit within the approved input categories. Preferred vendors are prioritized in purchase order generation and sourcing decisions for this farm unit.',
    CONSTRAINT pk_farm_vendor_approval PRIMARY KEY(`farm_vendor_approval_id`)
) COMMENT 'This association product represents the Contract between farm_unit and vendor. It captures the formal approval of a specific vendor to supply designated agricultural input categories to a specific farm unit, including farm-level pricing agreements, preferred supplier status, and approval validity periods. Each record links one farm_unit to one vendor and carries attributes that exist only in the context of this farm-unit-specific vendor authorization — data that belongs neither to the farm unit master nor to the vendor master alone.. Existence Justification: In agricultural operations, a farm unit actively approves and manages multiple vendors for input supply (seed, fertilizer, agrochemicals, fuel), and a single vendor supplies inputs to multiple farm units across a region or enterprise. This is not an analytical correlation — procurement teams explicitly create, maintain, and expire farm-unit-level vendor approvals with farm-specific pricing agreements, approved input categories, and validity periods. The relationship is operationally managed as a Vendor Approval or Supply Agreement record that procurement and farm managers actively govern.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`land`.`land_field_operation` (
    `land_field_operation_id` BIGINT COMMENT 'Primary key for the field_operation association',
    `account_id` BIGINT COMMENT 'Foreign key linking this operation record to the customer account (landowner, tenant, or custom operator) holding the operational role on this field.',
    `field_id` BIGINT COMMENT 'Foreign key linking this operation record to the specific agricultural field or paddock being operated.',
    `acres_operated` DECIMAL(18,2) COMMENT 'The number of acres (or hectares, per enterprise convention) of this field that fall under this accounts operational responsibility. May be less than the fields total_area_ha in partial-field arrangements (e.g., split leases, strip farming). Belongs to the relationship — neither the field nor the account alone can hold this value.',
    `effective_date` DATE COMMENT 'The date from which this operator role on this field is considered active and authoritative. Required for FSA farm records and crop insurance operator declarations. Belongs to the relationship, not to the field or account alone.',
    `expiry_date` DATE COMMENT 'The date on which this operator role on this field expires or is superseded. Null indicates an open-ended current relationship. Enables historical tracking of who operated which field and when — critical for crop insurance audits and FSA compliance.',
    `operation_type` STRING COMMENT 'The specific agricultural operation(s) the account is authorized or contracted to perform on this field under this role. Distinguishes, for example, a custom operator engaged only for harvest from one engaged for full-season crop production. Belongs to the relationship.',
    `operator_role` STRING COMMENT 'The specific operational capacity in which the account is associated with this field. Drives FSA operator declarations, crop insurance eligibility, and billing logic. Belongs to the relationship — the same account may be a tenant on one field and a custom operator on another.',
    CONSTRAINT pk_land_field_operation PRIMARY KEY(`land_field_operation_id`)
) COMMENT 'This association product represents the operational role relationship between a field and a customer account. It captures who operates a given field, in what capacity, and for what period — supporting FSA farm records, crop insurance operator declarations, lease management, and custom farming billing. Each record links one field to one account with a specific operator role and effective date range. A field may have multiple simultaneous records (e.g., one landowner + one tenant + one custom operator), and one account may have many such records across its entire field portfolio.. Existence Justification: In agricultural operations, a single field can be simultaneously operated by multiple accounts in different capacities — a landowner account holds title, a cash-rent tenant account farms the ground, and a custom operator account may perform specific operations (e.g., harvesting). Conversely, one account (e.g., a large farming operation or custom operator) manages many fields across multiple farm units. The business actively tracks these operator relationships for FSA farm records, crop insurance eligibility, and operational billing — this is not a derived correlation but an actively managed operational record.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`land`.`field_input_restriction` (
    `field_input_restriction_id` BIGINT COMMENT 'Primary key for the field_input_restriction association',
    `field_id` BIGINT COMMENT 'Foreign key linking to the agricultural field or paddock on which the input restriction applies',
    `input_product_id` BIGINT COMMENT 'Foreign key linking to the agricultural input product that is restricted on the associated field',
    `effective_date` DATE COMMENT 'The date from which this field-input restriction is considered active and operationally enforced. Typically aligned with the start of an organic certification period, conservation contract enrollment date, or regulatory advisory issuance date.',
    `expiry_date` DATE COMMENT 'The date on which this restriction lapses or is no longer applicable. May be null for indefinite restrictions. Examples: expiry of organic certification, end of FSA conservation contract term, or lifting of a groundwater advisory.',
    `is_active` BOOLEAN COMMENT 'Indicates whether this restriction is currently in force. Derived from effective_date and expiry_date but maintained as an explicit operational flag to support fast compliance queries during application planning and spray record generation.',
    `regulatory_basis` STRING COMMENT 'The regulatory or policy authority underpinning this restriction. Drives compliance reporting and audit trail. Aligned with USDA NOP, EPA FIFRA, and FSA program requirements.',
    `restriction_reason` STRING COMMENT 'Human-readable explanation of why this input product is restricted on this field. Examples: Organic certification prohibits synthetic inputs, Groundwater advisory — sandy soil over aquifer recharge zone, FSA conservation contract CRP enrollment, GMO-restricted field boundary.',
    `restriction_type` STRING COMMENT 'Classification of how the input product is restricted on this field. prohibited means no application permitted; rate_limited means application is allowed below a maximum rate; buffer_zone_only means application is excluded within a defined distance of a waterway or boundary; timing_restricted means application is only permitted outside certain windows (e.g., pre-planting only); conditional means restriction applies only under specific conditions.',
    CONSTRAINT pk_field_input_restriction PRIMARY KEY(`field_input_restriction_id`)
) COMMENT 'This association product represents the regulatory and operational restriction Contract between a field and an agricultural input product. It captures the specific restriction governing whether and how a given input product may be applied to a given field, driven by organic certification, groundwater advisories, conservation program enrollment, GMO restrictions, or other regulatory requirements. Each record links one field to one input_product and carries the restriction type, regulatory basis, effective period, and reason — data that exists only in the context of this specific field-product pairing.. Existence Justification: In agricultural operations, a field can have multiple input product restrictions simultaneously (e.g., an organic-certified field restricts all synthetic pesticides, while a field near a waterway restricts specific herbicides, and a conservation-enrolled field restricts certain soil amendments). Conversely, a single input product (e.g., a restricted-use herbicide) is restricted on many different fields across the farm for different regulatory reasons. The business actively manages these restrictions — creating, updating, and expiring them — as a compliance and operational control mechanism with its own regulatory basis, effective dates, and restriction type.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`land`.`field_certification_scope` (
    `field_certification_scope_id` BIGINT COMMENT 'Primary key for the field_certification_scope association',
    `field_id` BIGINT COMMENT 'Foreign key linking to the agricultural field or paddock covered under this certification scope record.',
    `sustainability_certification_id` BIGINT COMMENT 'Foreign key linking to the sustainability certification master record under which this field is scoped.',
    `audit_score` DECIMAL(18,2) COMMENT 'The numeric audit score or percentage achieved for this specific field during the most recent certification audit. Per-field scores may differ across fields covered by the same certificate, particularly for farm-level certifications spanning multiple paddocks.',
    `certification_status` STRING COMMENT 'Per-field certification status under this scope record. A field may be suspended or withdrawn from a certification while other fields under the same certificate remain active — this per-field status is distinct from the master certification_status on the sustainability_certification record.',
    `certified_area_ha` DECIMAL(18,2) COMMENT 'The portion of this specific fields area that is covered and certified under this certification scope record, in hectares. May be less than the fields total_area_ha if only part of the field is in scope. Distinct from the certification masters aggregate certified_area_ha.',
    `effective_date` DATE COMMENT 'The date from which this field is operationally in scope for this certification. May differ from the master certificates effective_date if the field was added to the certification scope after initial issuance.',
    `expiry_date` DATE COMMENT 'The date on which this fields coverage under this certification lapses. May differ from the master certificates expiry_date if the fields scope was granted for a shorter period or is subject to a separate renewal cycle.',
    `organic_certified` BOOLEAN COMMENT 'Indicates whether the field holds active USDA National Organic Program (NOP) certification. Drives input restriction rules, segregation requirements, and organic premium pricing in sales and procurement workflows. [Moved from field: This boolean flag on field is a denormalised indicator that duplicates information now captured structurally in the field_certification_scope association (where USDA Organic certification coverage is a specific scope record). Once the association is in place, organic certification status for a field is derivable by querying field_certification_scope for scheme_name = USDA Organic with certification_status = active. Retaining the boolean creates a dual-maintenance risk and potential inconsistency.]',
    CONSTRAINT pk_field_certification_scope PRIMARY KEY(`field_certification_scope_id`)
) COMMENT 'This association product represents the Contract between a specific agricultural field and a sustainability certification. It captures the operational scope record that defines which fields are covered under each certification, the certified area applicable to that field, the per-field certification status, audit findings, and the effective and expiry dates of coverage. Each record links one field to one sustainability_certification with attributes that exist only in the context of this field-level certification scope — data that belongs neither to the field master record nor to the certification master record alone.. Existence Justification: In agricultural operations, a single field genuinely holds multiple simultaneous certifications (e.g., USDA Organic + GlobalG.A.P. + Rainforest Alliance applied to the same paddock at the same time), and a single certification (e.g., a farm-level USDA Organic certificate) covers multiple fields within that farm unit. The business actively manages this relationship — compliance teams track which fields are in scope for each certification, what certified area applies per field, and the per-field audit status. This is not an analytical derivation; it is an operational record that auditors, certification bodies, and farm managers create, update, and query directly.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`land`.`farm_operation` (
    `farm_operation_id` BIGINT COMMENT 'Primary key for farm_operation',
    `employee_id` BIGINT COMMENT 'Reference to the primary operator or owner responsible for managing this farm operation.',
    `facility_id` BIGINT COMMENT 'External identifier linking this farm operation to John Deere Operations Center or similar farm management platform.',
    `parent_farm_operation_id` BIGINT COMMENT 'Self-referencing FK on farm_operation (parent_farm_operation_id)',
    `bmp_compliance_status` STRING COMMENT 'Current compliance status with agricultural best management practices for environmental stewardship.',
    `centroid_latitude` DECIMAL(18,2) COMMENT 'Geographic latitude coordinate of the farm operation centroid in decimal degrees, using WGS84 datum.',
    `centroid_longitude` DECIMAL(18,2) COMMENT 'Geographic longitude coordinate of the farm operation centroid in decimal degrees, using WGS84 datum.',
    `conservation_plan_date` DATE COMMENT 'Date when the current conservation plan was approved or last updated.',
    `conservation_plan_status` STRING COMMENT 'Current status of the farm conservation plan required for environmental compliance and best management practices.',
    `country_code` STRING COMMENT 'Three-letter ISO country code for the country where the farm operation is located.',
    `county_fips_code` STRING COMMENT 'Five-digit FIPS code identifying the county where the farm operation is primarily located.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this farm operation record was first created in the system.',
    `cultivated_acreage` DECIMAL(18,2) COMMENT 'Total acreage actively used for crop cultivation within the farm operation.',
    `established_date` DATE COMMENT 'Date when the farm operation was originally established or registered.',
    `gis_boundary_reference` STRING COMMENT 'Reference identifier linking to the GIS-mapped field boundary polygon in ArcGIS or spatial database systems.',
    `irrigation_system_type` STRING COMMENT 'Primary type of irrigation system used on the farm operation, if applicable.',
    `iso_14001_certified` BOOLEAN COMMENT 'Indicates whether the farm operation holds ISO 14001 environmental management system certification.',
    `last_inspection_date` DATE COMMENT 'Date of the most recent regulatory or compliance inspection conducted on the farm operation.',
    `legal_entity_type` STRING COMMENT 'Legal structure under which the farm operation is organized and registered.',
    `modified_timestamp` TIMESTAMP COMMENT 'Timestamp when this farm operation record was last modified or updated.',
    `next_inspection_due_date` DATE COMMENT 'Scheduled date for the next regulatory or compliance inspection of the farm operation.',
    `notes` STRING COMMENT 'Free-text field for additional notes, comments, or special considerations related to the farm operation.',
    `operation_code` STRING COMMENT 'Externally-known unique business identifier or registration code for the farm operation, often used in regulatory filings and government programs.',
    `operation_name` STRING COMMENT 'The official business name or designation of the farm operation.',
    `operation_status` STRING COMMENT 'Current operational status of the farm operation in its lifecycle.',
    `operation_type` STRING COMMENT 'Primary classification of the farm operation based on its main agricultural activity.',
    `organic_certification_number` STRING COMMENT 'Official certification number issued by the organic certifying agency, if applicable.',
    `organic_certified` BOOLEAN COMMENT 'Indicates whether the farm operation holds valid organic certification from an accredited certifying body.',
    `ownership_type` STRING COMMENT 'Primary ownership or tenure arrangement for the land managed by this farm operation.',
    `precision_agriculture_enabled` BOOLEAN COMMENT 'Indicates whether the farm operation utilizes precision agriculture technologies such as GPS guidance, variable rate application, or yield monitoring.',
    `primary_commodity` STRING COMMENT 'The main agricultural commodity or crop produced by this farm operation.',
    `registration_date` DATE COMMENT 'Date when the farm operation was registered in the system or with regulatory authorities.',
    `rtk_gps_enabled` BOOLEAN COMMENT 'Indicates whether the farm operation uses RTK-accurate GPS positioning for field operations and mapping.',
    `secondary_commodity` STRING COMMENT 'The secondary agricultural commodity or crop produced by this farm operation, if applicable.',
    `state_code` STRING COMMENT 'Two-letter postal abbreviation for the state where the farm operation is located.',
    `tax_identification_number` STRING COMMENT 'Federal tax identification number (EIN or SSN) associated with the farm operation for tax reporting purposes.',
    `total_acreage` DECIMAL(18,2) COMMENT 'Total land area in acres managed by this farm operation, including cultivated, pasture, and non-productive land.',
    `water_source_type` STRING COMMENT 'Primary source of water used for irrigation and farm operations.',
    CONSTRAINT pk_farm_operation PRIMARY KEY(`farm_operation_id`)
) COMMENT 'Master reference table for farm_operation. Referenced by farm_operation_id.';

